import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";

// Initialize Gemini Client
// Assumption: process.env.API_KEY is available in the environment
const apiKey = process.env.API_KEY || ''; 

let chatSession: Chat | null = null;

export const initializeChat = (): Chat => {
  if (chatSession) return chatSession;

  if (!apiKey) {
    console.warn("API Key is missing. AI features will not work.");
    // Return a dummy object or handle gracefully in UI
  }

  const ai = new GoogleGenAI({ apiKey });

  chatSession = ai.chats.create({
    model: 'gemini-2.5-flash',
    config: {
      systemInstruction: `
        Você é o Consultor Virtual da Universidade Anhanguera, especialista na Pós-Graduação em Nutrição Clínica.

        Seu objetivo é convencer potenciais alunos a se matricularem, tirando dúvidas de forma empática, profissional e persuasiva.

        Informações do curso:
        - Nome: Pós-graduação em Nutrição Clínica.
        - Modalidade: 100% Online ou Híbrido.
        - Duração: 10 meses (intensivo) ou 18 meses.
        - Público-alvo: Nutricionistas graduados.
        - Diferenciais: Corpo docente renomado, plataforma moderna, certificação reconhecida pelo MEC.
        - Preço: A partir de R$ 149,90 mensais (bolsas disponíveis).

        Regras de conduta:
        1. Seja breve e direto (máximo 3 frases por resposta).
        2. Use um tom acolhedor e motivador.
        3. Sempre termine convidando para a inscrição ou para falar com um humano se a dúvida for complexa.
        4. Responda apenas perguntas sobre nutrição, carreira e o curso.
      `,
    },
  });

  return chatSession;
};

export const sendMessageToGemini = async (message: string): Promise<string> => {
  try {
    const chat = initializeChat();
    const result: GenerateContentResponse = await chat.sendMessage({ message });
    return result.text || "Desculpe, não consegui entender. Poderia reformular?";
  } catch (error) {
    console.error("Error sending message to Gemini:", error);
    return "Ocorreu um erro momentâneo. Por favor, tente novamente em alguns instantes.";
  }
};

