// --- Chat Widget (Redesigned) ---

const ChatWidget = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{id: number, text: string, sender: 'bot' | 'user'}[]>([
    { id: 1, text: "Olá! Sou a Ana, consultora acadêmica. Como posso te ajudar a escolher sua especialização?", sender: 'bot' }
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => messagesEndRef.current?.scrollIntoView({ behavior: "smooth" }), [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = { id: Date.now(), text: input, sender: 'user' as const };
    setMessages(prev => [...prev, userMsg]);
    setInput("");
    setIsLoading(true);

    const responseText = await sendMessageToGemini(input);

    setMessages(prev => [...prev, { id: Date.now() + 1, text: responseText, sender: 'bot' }]);
    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
       {isOpen && (
         <div className="glass-high bg-white rounded-[2rem] shadow-2xl w-[90vw] md:w-[380px] h-[500px] mb-4 border border-white flex flex-col overflow-hidden animate-[float_0.3s_ease-out]">
            {/* Header */}
            <div className="p-5 border-b border-gray-100 bg-[#FDFCF8] flex justify-between items-center">
               <div className="flex items-center gap-3">
                 <div className="w-10 h-10 rounded-full bg-orange-100 flex items-center justify-center">
                    <img src={IMAGES.avatar1} className="w-full h-full rounded-full object-cover" alt="Bot"/>
                 </div>
                 <div>
                    <h4 className="font-bold text-gray-900 text-sm">Ana Consultora</h4>
                    <p className="text-xs text-green-600 font-medium flex items-center gap-1">
                      <span className="w-1.5 h-1.5 bg-green-500 rounded-full"></span> Online
                    </p>
                 </div>
               </div>
               <button onClick={() => setIsOpen(false)} className="text-gray-400 hover:text-gray-600"><X size={20}/></button>
            </div>

            {/* Chat Body */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-[#FAFAF9]">
               {messages.map(msg => (
                 <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[80%] p-4 text-sm leading-relaxed shadow-sm ${
                      msg.sender === 'user' 
                      ? 'bg-[#1c1917] text-white rounded-[20px] rounded-br-sm' 
                      : 'bg-white text-gray-700 border border-gray-100 rounded-[20px] rounded-bl-sm'
                    }`}>
                      {msg.text}
                    </div>
                 </div>
               ))}
               {isLoading && (
                 <div className="flex justify-start">
                    <div className="bg-white border border-gray-100 p-4 rounded-[20px] rounded-bl-sm shadow-sm">
                      <div className="flex gap-1.5">
                        <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce"></span>
                        <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce delay-75"></span>
                        <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce delay-150"></span>
                      </div>
                    </div>
                 </div>
               )}
               <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <div className="p-4 bg-white border-t border-gray-100">
               <div className="relative">
                 <input 
                   type="text" 
                   value={input}
                   onChange={(e) => setInput(e.target.value)}
                   onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                   placeholder="Digite sua dúvida..."
                   className="w-full bg-gray-50 border border-gray-200 rounded-full pl-5 pr-12 py-3 text-sm focus:outline-none focus:border-[#F94E12] transition-colors"
                 />
                 <button 
                   onClick={handleSend}
                   disabled={!input.trim() || isLoading}
                   className="absolute right-2 top-1/2 -translate-y-1/2 w-8 h-8 bg-[#F94E12] text-white rounded-full flex items-center justify-center hover:bg-[#d83e0c] disabled:opacity-50 transition-colors"
                 >
                   <Send size={14}/>
                 </button>
               </div>
            </div>
         </div>
       )}

       <button 
         onClick={() => setIsOpen(!isOpen)}
         className="w-14 h-14 bg-[#1c1917] text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-105 transition-transform"
       >
         {isOpen ? <X/> : <MessageCircle/>}
       </button>
    </div>
  );
};

