import React, { useState } from 'react';
import { ArtifactType } from '../types';

interface InputFormProps {
    artifactType: ArtifactType;
    onSubmit: (context: string) => void;
    isLoading: boolean;
}

const placeholders: { [key in ArtifactType]: string } = {
    [ArtifactType.Observation]: 'Cole aqui suas anotações ou transcrições de observações...',
    [ArtifactType.InterviewQuestions]: 'Descreva o problema ou o contexto para o qual você precisa de perguntas de entrevista...',
    [ArtifactType.SummarizeInterview]: 'Cole aqui a transcrição completa da entrevista para ser resumida...',
    [ArtifactType.Personas]: 'Forneça o máximo de contexto sobre seu usuário-alvo: dados demográficos, comportamentos, necessidades, etc.',
    [ArtifactType.AgentModel]: 'Descreva os papéis e atores do sistema para gerar o Modelo de Agentes CommonKADS...',
    [ArtifactType.EmpathyMap]: 'Descreva a situação e o usuário para o qual o mapa de empatia será criado...',
    [ArtifactType.MOTables]: 'Descreva o contexto organizacional, os problemas e oportunidades identificados para gerar o Modelo Organizacional (CommonKADS)...',
    [ArtifactType.HypothesisGeneration]: 'Descreva o problema, a oportunidade ou os insights de pesquisa para gerarmos hipóteses de solução...',
    [ArtifactType.FunctionalRequirements]: 'Descreva as funcionalidades principais, objetivos do sistema ou histórias de usuário para gerar a lista de requisitos...',
    [ArtifactType.UserFlows]: 'Descreva a tarefa ou funcionalidade para a qual o fluxo de usuário será desenhado...',
    [ArtifactType.UIScreens]: 'Descreva em detalhes a tela que você quer gerar. Inclua funcionalidades, elementos e o objetivo da tela.',
};

const InputForm: React.FC<InputFormProps> = ({ artifactType, onSubmit, isLoading }) => {
    const [text, setText] = useState('');
    const [fileContent, setFileContent] = useState('');
    const [fileName, setFileName] = useState('');

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setFileName(file.name);
        const reader = new FileReader();
        reader.onload = (event) => {
            const content = event.target?.result as string;
            setFileContent(content);
        };
        reader.readAsText(file);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!text && !fileContent) return;
        const combinedContext = `${text}\n\n${fileContent ? `--- Conteúdo do arquivo: ${fileName} ---\n${fileContent}` : ''}`;
        onSubmit(combinedContext.trim());
    };

    const canUploadFile = artifactType === ArtifactType.Observation || artifactType === ArtifactType.SummarizeInterview;

    return (
        <form onSubmit={handleSubmit} className="space-y-5">
            <div className="relative group">
                <label htmlFor="context-input" className="block text-sm font-medium text-gray-300 mb-2 ml-1">
                    Forneça o contexto necessário:
                </label>
                <div className="absolute -inset-0.5 bg-gradient-to-r from-orange-500 to-amber-500 rounded-lg opacity-20 group-hover:opacity-40 transition duration-500 blur"></div>
                <textarea
                    id="context-input"
                    value={text}
                    onChange={(e) => setText(e.target.value)}
                    placeholder={placeholders[artifactType]}
                    rows={8}
                    className="relative w-full p-4 bg-zinc-900/80 backdrop-blur-sm border border-white/10 rounded-lg focus:ring-2 focus:ring-orange-500/50 focus:border-orange-500/50 transition text-gray-100 placeholder-gray-500 shadow-inner"
                    disabled={isLoading}
                />
            </div>

            {canUploadFile && (
                 <div className="p-4 rounded-lg bg-zinc-800/30 border border-white/5 border-dashed">
                    <label htmlFor="file-upload" className="block text-sm font-medium text-gray-400 mb-2">
                        Ou envie um arquivo de transcrição (.txt):
                    </label>
                    <input 
                        type="file" 
                        id="file-upload"
                        onChange={handleFileChange} 
                        accept=".txt,text/plain"
                        className="block w-full text-sm text-gray-400 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-orange-600/80 file:text-white hover:file:bg-orange-600 file:transition-colors cursor-pointer"
                        disabled={isLoading}
                    />
                    {fileName && <p className="text-xs text-green-400 mt-2 flex items-center"><span className="mr-1">✓</span> Arquivo carregado: {fileName}</p>}
                </div>
            )}

            <button
                type="submit"
                disabled={isLoading || (!text && !fileContent)}
                className="w-full flex justify-center py-3 px-4 border border-transparent rounded-xl shadow-lg shadow-orange-900/30 text-sm font-bold text-white bg-gradient-to-r from-orange-600 to-amber-600 hover:from-orange-500 hover:to-amber-500 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500 disabled:from-zinc-700 disabled:to-zinc-800 disabled:text-gray-500 disabled:cursor-not-allowed transition-all duration-300 transform hover:scale-[1.02]"
            >
                {isLoading ? 'Gerando...' : 'Gerar Artefato'}
            </button>
        </form>
    );
};

export default InputForm;

import { GoogleGenAI, Type } from "@google/genai";
import { ArtifactType, GeneratedArtifact } from '../types';

const API_KEY = process.env.API_KEY;
if (!API_KEY) {
    throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const safeParseJson = (jsonString: string): any => {
    // Attempt to find JSON within markdown code fences
    const match = jsonString.match(/```(json)?\s*([\s\S]*?)\s*```/);
    let textToParse = jsonString.trim();

    if (match && match[2]) {
        textToParse = match[2];
    } else {
        // Fallback for cases where there are no code fences, but maybe leading/trailing text
        const firstBrace = textToParse.indexOf('{');
        const lastBrace = textToParse.lastIndexOf('}');
        if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
            textToParse = textToParse.substring(firstBrace, lastBrace + 1);
        }
    }

    try {
        let parsed = JSON.parse(textToParse);
        // Handle cases where the model returns a stringified JSON object
        if (typeof parsed === 'string') {
            parsed = JSON.parse(parsed);
        }
        return parsed;
    } catch (error) {
        console.error("Failed to parse JSON:", textToParse);
        throw new Error("Received invalid JSON from the model.");
    }
};

export const suggestPersonasFromContext = async (context: string): Promise<string[]> => {
    const prompt = `Atue como um UX Researcher Sênior. Analise o contexto do projeto fornecido abaixo e identifique de 1 a 3 personas (papéis, profissões ou arquétipos de usuários) que são mais críticas para este projeto.

Contexto do Projeto:
${context}

Retorne APENAS um array JSON de strings contendo os nomes dessas personas.
Exemplo de saída: ["Estudante Universitário", "Professor de Ensino Médio"]`;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                }
            }
        });

        const parsed = safeParseJson(response.text);
        if (Array.isArray(parsed)) {
            return parsed;
        }
        return [];
    } catch (error) {
        console.error("Error suggesting personas:", error);
        return [];
    }
};

const getObservationSummary = async (context: string): Promise<GeneratedArtifact> => {
    const prompt = `Atue como um Especialista em UX Research Sênior. Sua tarefa é analisar as notas de observação fornecidas e criar um relatório de síntese estruturado.

O relatório deve conter as seguintes seções em Markdown:
1. **Contexto e Ambiente**: Onde e quando a observação ocorreu? O que estava acontecendo ao redor?
2. **Comportamentos Chave**: O que o usuário fez? Descreva as ações sequencialmente ou por relevância.
3. **Pontos de Dor (Pain Points)**: Quais dificuldades, barreiras ou frustrações o usuário encontrou?
4. **Gambiarra/Soluções de Contorno**: O usuário inventou alguma maneira não oficial de resolver um problema?
5. **Oportunidades de Design**: Com base no que foi visto, quais são as oportunidades imediatas de melhoria?

REGRAS DE SAÍDA:
- NÃO INCLUA NENHUM TEXTO DE INTRODUÇÃO (Ex: "Como especialista...", "Aqui está o relatório").
- Comece a resposta DIRETAMENTE pelo primeiro título ou tópico em Markdown.

Contexto da Observação:
${context}`;
    const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: prompt
    });
    return { text: response.text };
};

const getInterviewQuestions = async (context: string): Promise<GeneratedArtifact> => {
    const prompt = `Atue como um Especialista em UX Research. Com base no contexto fornecido, crie um roteiro de entrevista semi-estruturado.

O objetivo é aprofundar o entendimento sobre as motivações e problemas do usuário.
Estruture a resposta em Markdown com as seguintes categorias:

1. **Quebra-Gelo e Introdução**: 3-4 perguntas para deixar o participante à vontade e entender seu perfil básico.
2. **Exploração do Problema/Tarefa**: Perguntas abertas ("Conte-me sobre a última vez que...", "Como você lida com...") focadas em fatos e comportamentos passados, não em opiniões futuras.
3. **Aprofundamento (Os 'Porquês')**: Perguntas de follow-up para entender a raiz das frustrações.
4. **Encerramento**: Perguntas finais para capturar algo que não foi coberto.

Evite perguntas de "sim/não". Priorize perguntas que evoquem histórias.

REGRAS DE SAÍDA:
