const getEmpathyMap = async (context: string): Promise<GeneratedArtifact> => {
    // 1. Identify Personas in the context
    const identificationPrompt = `
    Analise o texto abaixo e identifique se existem Personas já definidas (procure por seções como "# Nome: Papel" ou listas de personas).

    Se houver personas definidas, retorne uma lista JSON com seus nomes e papéis.
    Se NÃO houver personas definidas explicitamente, retorne uma lista vazia [].

    Contexto:
    ${context}
    `;

    let targets: { name: string; role: string }[] = [];

    try {
        const idResponse = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: identificationPrompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            name: { type: Type.STRING },
                            role: { type: Type.STRING }
                        }
                    }
                }
            }
        });
        targets = safeParseJson(idResponse.text);
    } catch (e) {
        console.warn("Failed to identify personas, falling back to generic.");
    }

    // Fallback if no personas found
    if (targets.length === 0) {
        targets.push({ name: "Usuário Típico", role: "Usuário Principal do Sistema" });
    }

    let fullMarkdown = "# Mapas de Empatia\n\n";
    let firstImageUrl: string | undefined = undefined;

    // 2. Loop through each persona to generate Map Data and Image
    for (const target of targets) {
        const personaLabel = `${target.name} (${target.role})`;

        // A. Generate Data
        const dataPrompt = `Atue como um UX Designer. Crie um Mapa de Empatia detalhado para a persona: ${personaLabel}.

        Analise o contexto do projeto e preencha os 6 quadrantes especificamente para esta persona.
        Para cada quadrante (exceto Pains e Gains), forneça exatamente 3 a 5 itens curtos e diretos (como se fossem post-its).

        Contexto do Projeto:
        ${context}`;

        let empathyData: any = {};

        try {
            const response = await ai.models.generateContent({
                model: "gemini-2.5-flash",
                contents: dataPrompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            see: { type: Type.ARRAY, items: { type: Type.STRING }, description: "O que ela vê?" },
                            hear: { type: Type.ARRAY, items: { type: Type.STRING }, description: "O que ela ouve?" },
                            thinkAndFeel: { type: Type.ARRAY, items: { type: Type.STRING }, description: "O que ela pensa e sente?" },
                            sayAndDo: { type: Type.ARRAY, items: { type: Type.STRING }, description: "O que ela fala e faz?" },
                            pains: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Dores" },
                            gains: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Ganhos" }
                        },
                        required: ["see", "hear", "thinkAndFeel", "sayAndDo", "pains", "gains"]
                    }
                }
            });
            empathyData = safeParseJson(response.text);
        } catch (error) {
            console.error(`Error generating text for Empathy Map of ${target.name}`, error);
            continue; 
        }

        // B. Generate Image (Nano Banana)
        let currentImageUrl: string | null = null;
        try {
            const getItemsForPrompt = (arr: string[]) => arr ? arr.slice(0, 4).join("', '") : "";

            const imagePrompt = `
            Create a high-quality, professional UX Empathy Map diagram drawn on a clean white surface or whiteboard for persona: "${target.name} - ${target.role}".
            The image must be divided into 4 clear quadrants with a central user icon representing this specific persona.

            Visually represent sticky notes (Post-its) in each section containing the following text summaries (translated to English for visual rendering if needed, but context is Portuguese):

            1. TOP LEFT (THINK & FEEL) - Blue Sticky Notes containing text: '${getItemsForPrompt(empathyData.thinkAndFeel)}'
            2. TOP RIGHT (SEE) - Yellow Sticky Notes containing text: '${getItemsForPrompt(empathyData.see)}'
            3. BOTTOM LEFT (HEAR) - Pink Sticky Notes containing text: '${getItemsForPrompt(empathyData.hear)}'
            4. BOTTOM RIGHT (SAY & DO) - Green Sticky Notes containing text: '${getItemsForPrompt(empathyData.sayAndDo)}'

            Ensure the text on the sticky notes is legible, handwritten style. 
            The layout should be clean, organized, and colorful. 4k resolution, design thinking workshop style.
            `;

            const imageResponse = await ai.models.generateContent({
                model: 'gemini-2.5-flash-image',
                contents: { parts: [{ text: imagePrompt }] }
            });

            if (imageResponse.candidates && imageResponse.candidates[0].content && imageResponse.candidates[0].content.parts) {
                for (const part of imageResponse.candidates[0].content.parts) {
                    if (part.inlineData) {
                        currentImageUrl = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
                        if (!firstImageUrl) firstImageUrl = currentImageUrl;
                        break;
                    }
                }
            }
        } catch (imageError) {
            console.error(`Error generating image for ${target.name}`, imageError);
        }

        // C. Construct Markdown for this Persona
        const imageMarkdown = currentImageUrl ? `\n![Mapa de Empatia - ${target.name}](${currentImageUrl})\n` : "";

        const personaMarkdown = `
## Persona: ${target.name}
${imageMarkdown}

### 1. O QUE ELA VÊ?
${empathyData.see?.map((i: string) => `- ${i}`).join('\n') || ''}

### 2. O QUE ELA OUVE?
${empathyData.hear?.map((i: string) => `- ${i}`).join('\n') || ''}

### 3. O QUE ELA PENSA E SENTE?
${empathyData.thinkAndFeel?.map((i: string) => `- ${i}`).join('\n') || ''}

### 4. O QUE ELA FALA E FAZ?
${empathyData.sayAndDo?.map((i: string) => `- ${i}`).join('\n') || ''}

### 5. DORES (PAINS)
${empathyData.pains?.map((i: string) => `- ${i}`).join('\n') || ''}

### 6. GANHOS (GAINS)
${empathyData.gains?.map((i: string) => `- ${i}`).join('\n') || ''}

---
`;
        fullMarkdown += personaMarkdown;
    }

    return { text: fullMarkdown.trim(), imageUrl: firstImageUrl };
};

// Helper to generate an image for a persona using Nano Banana (gemini-2.5-flash-image)
const generatePersonaImage = async (visualDescription: string): Promise<string | null> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [
                    { text: `Create a realistic, professional, high-quality portrait photo of a person matching this description: ${visualDescription}. The background should be blurred and neutral. Focus on the face and expression.` }
                ]
            }
        });

        // Iterate through parts to find the image
        if (response.candidates && response.candidates[0].content && response.candidates[0].content.parts) {
            for (const part of response.candidates[0].content.parts) {
                if (part.inlineData) {
                    return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
                }
            }
        }
        return null;
    } catch (error) {
        console.error("Error generating persona image:", error);
        return null;
    }
};

const getPersona = async (context: string): Promise<GeneratedArtifact> => {
    // 1. Generate the textual content for personas
    const textPrompt = `Atue como um UX Strategist.

    TAREFA: Crie Personas detalhadas baseadas nos dados de pesquisa e nas instruções fornecidas no contexto.

    INSTRUÇÃO:
    - Analise o contexto para ver quantas personas foram sugeridas ou solicitadas.
    - Se houver múltiplas personas mencionadas, GERE UMA FICHA COMPLETA PARA CADA UMA DELAS.
    - Se nenhuma persona específica foi mencionada, identifique os principais arquétipos e gere pelo menos uma persona.

    A resposta deve ser formatada DIRETAMENTE em Markdown.
    Para cada Persona, use a seguinte estrutura (repita para quantas forem necessárias):

    ---
    # [Nome da Persona]: [Papel/Arquétipo]

    **Descrição Visual:** [Uma descrição física breve de 1 frase para gerar uma foto desta pessoa]

    > [Inclua uma Citação ou Lema marcante da persona aqui]

    ## Dados Demográficos
    (Idade, ocupação, estado civil, localização, etc)

    ## Bio
    (Breve história e contexto de vida)

    ## Objetivos e Motivações
    (O que ela quer alcançar?)

    ## Frustrações e Barreiras
    (O que a impede? Quais são suas dores?)

    ## Marcas e Tecnologia
    (O que ela usa e gosta?)
    ---

    REGRAS DE SAÍDA:
    - NÃO INCLUA TEXTO INTRODUTÓRIO (Ex: "Com base no contexto...", "Aqui estão as personas").
    - Comece a resposta imediatamente com "---" ou com o título da primeira persona.

    Contexto do Projeto:
    ${context}`;

    let generatedText = "";

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: textPrompt
        });
        generatedText = response.text;
    } catch (error) {
        console.error("Failed to generate persona text:", error);
        throw new Error("Não foi possível gerar as personas no momento.");
    }

    // 2. Extract personas and their visual descriptions to generate images
    // We will parse the generated text using regex to find the Header and the Visual Description

    // Regex to match: # Name: Role ... **Descrição Visual:** Description
    // We iterate through the text to find these blocks.
    const personaBlocksRegex = /# (.*?)\n\n\*\*Descrição Visual:\*\* (.*?)(?=\n)/g;

    let match;
    let modifiedText = generatedText;

    // Using a replacement strategy implies handling async operations. 
    // We'll collect replacements and apply them after.
    const replacements: { start: number, end: number, imageHtml: string, originalMatch: string }[] = [];

    // Since regex execution with global flag is stateful, we loop
    while ((match = personaBlocksRegex.exec(generatedText)) !== null) {
        const fullMatch = match[0];
        const name = match[1].trim(); // Not used in image gen prompt but useful for debugging
        const visualDescription = match[2].trim();

        // Generate image
        const base64Image = await generatePersonaImage(visualDescription);

        if (base64Image) {
            // Create Markdown image syntax. We use a data URI.
            // Format: ![Persona Name](data:image/png;base64,...)
            const imageMarkdown = `\n![${name}](${base64Image})\n`;

            // We want to replace the "Descrição Visual" line with the image
            // match[0] contains both the header and the visual description line.
            // We want to keep the header, remove the description line, and add the image.
            const newBlock = `# ${name}\n${imageMarkdown}`;

            replacements.push({
                start: match.index,
                end: match.index + fullMatch.length,
                imageHtml: newBlock,
                originalMatch: fullMatch
            });
        }
    }

    // Apply replacements in reverse order to not mess up indices
    for (let i = replacements.length - 1; i >= 0; i--) {
        const rep = replacements[i];
        modifiedText = modifiedText.substring(0, rep.start) + rep.imageHtml + modifiedText.substring(rep.end);
    }

    return { text: modifiedText };
};

const getAgentModel = async (context: string): Promise<GeneratedArtifact> => {
    const prompt = `Atue como um Engenheiro do Conhecimento especialista em CommonKADS (Schreiber, 2000).

    TAREFA: Com base nas Personas já definidas no contexto do projeto, gere o **Modelo de Agentes**.

    REGRAS CRÍTICAS DE FORMATAÇÃO E CONTEÚDO:
    1. **ANONIMIZAÇÃO TOTAL**: NÃO use nomes próprios de pessoas (como "Ana", "Carlos", "Maria", "João"). 
    2. **USO DE OCUPAÇÃO**: Refira-se aos agentes EXCLUSIVAMENTE pela sua Ocupação, Função ou Papel (ex: use "Agente: Médico" em vez de "Agente: Dr. Silva"; use "Agente: Estudante" em vez de "Agente: Ana").
    3. **NEGRITO**: Todos os rótulos das listas (ex: **Nome:**, **Papel:**) DEVEM estar em negrito.
    4. **SEM INTRODUÇÃO**: NÃO inclua textos como "Aqui está o modelo...". Comece direto pelo primeiro agente.

    INSTRUÇÃO:
    - Identifique as personas no contexto.
    - Abstraia cada persona para seu papel funcional no sistema.
    - Para CADA papel, crie a definição detalhada.
    - Nos textos descritivos, não cite nomes pessoais, apenas o cargo ou a função.

    Formato OBRIGATÓRIO para cada Agente (repita para cada papel identificado):

    ### Agente: [Nome da Ocupação/Função]

    *   **Nome:** (Repita a Ocupação/Função do agente: Médico, Paciente, Administrador, etc)
    *   **Papel:** (Frase curta explicando a atividade chave que esta função desenvolve no sistema)
    *   **Envolvidos:** (Listar as atividades/tarefas específicas em que esta função está envolvida)
    *   **Comunicação:** (Com quais outros papeis/sistemas esta função se comunica)
    *   **Conhecimento:** (Quais conhecimentos técnicos/específicos esta função exige)
    *   **Outras competências:** (Competências externas relevantes para a função)
    *   **Responsabilidades e restrições:** (O que a função deve garantir e seus limites de acesso)

    ---

    Contexto do Projeto:
    ${context}`;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash",
