const getEmpathyMap = async (context: string): Promise<GeneratedArtifact> => {
    // 1. Identify Personas in the context
    const identificationPrompt = `
    Analise o texto abaixo e identifique se existem Personas já definidas (procure por seções como "# Nome: Papel" ou listas de personas).

    Se houver personas definidas, retorne uma lista JSON com seus nomes e papéis.
    Se NÃO houver personas definidas explicitamente, retorne uma lista vazia [].

    Contexto:
    ${context}
    `;

    let targets: { name: string; role: string }[] = [];

    try {
        const idResponse = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: identificationPrompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            name: { type: Type.STRING },
                            role: { type: Type.STRING }
                        }
                    }
                }
            }
        });
        targets = safeParseJson(idResponse.text);
    } catch (e) {
        console.warn("Failed to identify personas, falling back to generic.");
    }

    // Fallback if no personas found
    if (targets.length === 0) {
        targets.push({ name: "Usuário Típico", role: "Usuário Principal do Sistema" });
    }

    let fullMarkdown = "# Mapas de Empatia\n\n";
    let firstImageUrl: string | undefined = undefined;

    // 2. Loop through each persona to generate Map Data and Image
    for (const target of targets) {
        const personaLabel = `${target.name} (${target.role})`;

        // A. Generate Data
        const dataPrompt = `Atue como um UX Designer. Crie um Mapa de Empatia detalhado para a persona: ${personaLabel}.

        Analise o contexto do projeto e preencha os 6 quadrantes especificamente para esta persona.
        Para cada quadrante (exceto Pains e Gains), forneça exatamente 3 a 5 itens curtos e diretos (como se fossem post-its).

        Contexto do Projeto:
        ${context}`;

        let empathyData: any = {};

        try {
            const response = await ai.models.generateContent({
                model: "gemini-2.5-flash",
                contents: dataPrompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            see: { type: Type.ARRAY, items: { type: Type.STRING }, description: "O que ela vê?" },
                            hear: { type: Type.ARRAY, items: { type: Type.STRING }, description: "O que ela ouve?" },
                            thinkAndFeel: { type: Type.ARRAY, items: { type: Type.STRING }, description: "O que ela pensa e sente?" },
                            sayAndDo: { type: Type.ARRAY, items: { type: Type.STRING }, description: "O que ela fala e faz?" },
                            pains: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Dores" },
                            gains: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Ganhos" }
                        },
                        required: ["see", "hear", "thinkAndFeel", "sayAndDo", "pains", "gains"]
                    }
                }
            });
            empathyData = safeParseJson(response.text);
        } catch (error) {
            console.error(`Error generating text for Empathy Map of ${target.name}`, error);
            continue; 
        }

        // B. Generate Image (Nano Banana)
        let currentImageUrl: string | null = null;
        try {
            const getItemsForPrompt = (arr: string[]) => arr ? arr.slice(0, 4).join("', '") : "";

            const imagePrompt = `
            Create a high-quality, professional UX Empathy Map diagram drawn on a clean white surface or whiteboard for persona: "${target.name} - ${target.role}".
            The image must be divided into 4 clear quadrants with a central user icon representing this specific persona.

            Visually represent sticky notes (Post-its) in each section containing the following text summaries (translated to English for visual rendering if needed, but context is Portuguese):

            1. TOP LEFT (THINK & FEEL) - Blue Sticky Notes containing text: '${getItemsForPrompt(empathyData.thinkAndFeel)}'
            2. TOP RIGHT (SEE) - Yellow Sticky Notes containing text: '${getItemsForPrompt(empathyData.see)}'
            3. BOTTOM LEFT (HEAR) - Pink Sticky Notes containing text: '${getItemsForPrompt(empathyData.hear)}'
            4. BOTTOM RIGHT (SAY & DO) - Green Sticky Notes containing text: '${getItemsForPrompt(empathyData.sayAndDo)}'

            Ensure the text on the sticky notes is legible, handwritten style. 
            The layout should be clean, organized, and colorful. 4k resolution, design thinking workshop style.
            `;

            const imageResponse = await ai.models.generateContent({
                model: 'gemini-2.5-flash-image',
                contents: { parts: [{ text: imagePrompt }] }
            });

            if (imageResponse.candidates && imageResponse.candidates[0].content && imageResponse.candidates[0].content.parts) {
                for (const part of imageResponse.candidates[0].content.parts) {
                    if (part.inlineData) {
                        currentImageUrl = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
                        if (!firstImageUrl) firstImageUrl = currentImageUrl;
                        break;
                    }
                }
            }
        } catch (imageError) {
            console.error(`Error generating image for ${target.name}`, imageError);
        }

        // C. Construct Markdown for this Persona
        const imageMarkdown = currentImageUrl ? `\n![Mapa de Empatia - ${target.name}](${currentImageUrl})\n` : "";

        const personaMarkdown = `
## Persona: ${target.name}
${imageMarkdown}

### 1. O QUE ELA VÊ?
${empathyData.see?.map((i: string) => `- ${i}`).join('\n') || ''}

### 2. O QUE ELA OUVE?
${empathyData.hear?.map((i: string) => `- ${i}`).join('\n') || ''}

### 3. O QUE ELA PENSA E SENTE?
${empathyData.thinkAndFeel?.map((i: string) => `- ${i}`).join('\n') || ''}

### 4. O QUE ELA FALA E FAZ?
${empathyData.sayAndDo?.map((i: string) => `- ${i}`).join('\n') || ''}

### 5. DORES (PAINS)
${empathyData.pains?.map((i: string) => `- ${i}`).join('\n') || ''}

### 6. GANHOS (GAINS)
${empathyData.gains?.map((i: string) => `- ${i}`).join('\n') || ''}

---
`;
        fullMarkdown += personaMarkdown;
    }

    return { text: fullMarkdown.trim(), imageUrl: firstImageUrl };
