import { GoogleGenAI, Type } from "@google/genai";
import { ArtifactType, GeneratedArtifact } from '../types';

const API_KEY = process.env.API_KEY;
if (!API_KEY) {
    throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const safeParseJson = (jsonString: string): any => {
    // Attempt to find JSON within markdown code fences
    const match = jsonString.match(/```(json)?\s*([\s\S]*?)\s*```/);
    let textToParse = jsonString.trim();

    if (match && match[2]) {
        textToParse = match[2];
    } else {
        // Fallback for cases where there are no code fences, but maybe leading/trailing text
        const firstBrace = textToParse.indexOf('{');
        const lastBrace = textToParse.lastIndexOf('}');
        const firstBracket = textToParse.indexOf('[');
        const lastBracket = textToParse.lastIndexOf(']');

        // Determine if it's an object or array and slice accordingly
        if (firstBracket !== -1 && lastBracket !== -1 && (firstBrace === -1 || firstBracket < firstBrace)) {
             textToParse = textToParse.substring(firstBracket, lastBracket + 1);
        } else if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
            textToParse = textToParse.substring(firstBrace, lastBrace + 1);
        }
    }

    try {
        let parsed = JSON.parse(textToParse);
        // Handle cases where the model returns a stringified JSON object
        if (typeof parsed === 'string') {
            parsed = JSON.parse(parsed);
        }
        return parsed;
    } catch (error) {
        console.error("Failed to parse JSON:", textToParse);
        throw new Error("Received invalid JSON from the model.");
    }
};

// Helper function to clean Mermaid code
const cleanMermaidCode = (code: string): string => {
    if (!code) return '';

    // 1. Remove markdown code blocks
    let clean = code.replace(/```mermaid/gi, '').replace(/```/g, '');

    // 2. Remove HTML tags explicitly (CRITICAL FIX)
    // Replace <br> variants with a newline escape valid in mermaid strings
    clean = clean.replace(/<br\s*\/?>/gi, '\\n'); 
    // Remove all other HTML tags
    clean = clean.replace(/<[^>]*>/g, '');

    // 3. Trim whitespace
    clean = clean.trim();

    // 4. Scan for valid keywords to remove conversational prefixes
    const keywords = [
        'graph', 'flowchart', 'sequenceDiagram', 'classDiagram', 
        'stateDiagram', 'stateDiagram-v2', 'erDiagram', 'gantt', 
        'pie', 'journey', 'mindmap', 'timeline'
    ];

    const lines = clean.split('\n');
    let startLineIndex = -1;

    for (let i = 0; i < lines.length; i++) {
      const trimmedLine = lines[i].trim();
      // Check if line starts with one of the keywords
      if (keywords.some(kw => trimmedLine.startsWith(kw))) {
        startLineIndex = i;
        break;
      }
    }

    if (startLineIndex !== -1) {
      clean = lines.slice(startLineIndex).join('\n');
    }

    // 5. Enforce quotes for node labels [text] -> ["text"]
    // This regex safely matches content inside brackets [] and ensures it is quoted.
    clean = clean.replace(/\[([\s\S]*?)\]/g, (match, content) => {
        let text = content.trim();
        if (!text) return '[]';

        // Remove existing quotes if they exist at boundaries to prevent double quoting
        if ((text.startsWith('"') && text.endsWith('"')) || (text.startsWith("'") && text.endsWith("'"))) {
            text = text.slice(1, -1);
        }

        // Escape inner double quotes
        text = text.replace(/"/g, "'");

        // Collapse newlines into spaces (unless escaped)
        text = text.replace(/[\r\n]+/g, " ");

        return `["${text}"]`;
    });

    // 6. Enforce quotes for rounded node labels (text) -> ("text")
    // Note: We skip if it looks like a function call or style class definition if possible, 
    // but for "graph TD", ( ) usually means a node with rounded edges.
    clean = clean.replace(/\(([\s\S]*?)\)/g, (match, content) => {
        let text = content.trim();
        if (!text) return '()';

        // Check if it's likely a node label (contains spaces or non-alphanumeric chars)
        // If it's just (A) or (Start), we might leave it, but quoting is safer for Mermaid.

        if ((text.startsWith('"') && text.endsWith('"')) || (text.startsWith("'") && text.endsWith("'"))) {
             text = text.slice(1, -1);
        }

        // Escape inner quotes and newlines
        text = text.replace(/"/g, "'").replace(/[\r\n]+/g, " ");

        return `("${text}")`;
    });

    return clean.trim();
};

