        const parsed = safeParseJson(response.text);

        if (Array.isArray(parsed) && parsed.length > 0) {
            // Map the parsed JSON to the SubArtifact structure
            const artifacts = parsed.map((item: any) => {
                const cleanCode = cleanMermaidCode(item.code || "");
                return {
                    title: item.title,
                    content: cleanCode,
                    type: 'mermaid' as const
                };
