        console.error("Error generating user flows:", error);
        // Fallback to single text generation if JSON fails
        const fallbackPrompt = `Crie um único diagrama Mermaid graph TD abrangendo o fluxo principal do sistema descrito no contexto. NÃO USE HTML. Use apenas texto entre aspas.\n${context}`;
        const fallbackResponse = await ai.models.generateContent({ model: "gemini-2.5-pro", contents: fallbackPrompt});
        const mermaidCode = cleanMermaidCode(fallbackResponse.text);

        return { 
            text: mermaidCode, 
            isMermaid: true 
        };
    }
};

const getUIScreens = async (context: string): Promise<GeneratedArtifact> => {
    const uiPrompt = `Atue como um Diretor de Arte de UI Design. Sua tarefa é escrever um prompt de geração de imagem textual altamente detalhado para criar uma tela de interface de alta fidelidade.

Considere as personas, o fluxo e os requisitos.
A resposta DEVE ser um objeto JSON com o campo "imagePrompt".

O "imagePrompt" deve descrever a tela visualmente para um modelo de IA generativa (como Imagen ou Midjourney):
- Descreva o tipo de tela (ex: Dashboard, Login, Feed, Detalhe de Produto).
- Defina o estilo visual (ex: Neomorfismo, Material Design, Minimalista, Dark Mode, Cores vibrantes).
- Descreva elementos específicos: Tipografia (Sans-serif, bold headers), Botões (arredondados, gradiente), Ícones (outline, filled).
- Descreva o conteúdo fictício visível para tornar a tela realista.

Contexto do Projeto: ${context}`;

    let uiData;
    const maxRetries = 2;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
        try {
            const uiResponse = await ai.models.generateContent({
                model: "gemini-2.5-pro",
                contents: uiPrompt,
                config: {
                  responseMimeType: "application/json",
                  responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                      imagePrompt: { type: Type.STRING },
                    }
                  }
                }
            });

            const parsedData = safeParseJson(uiResponse.text);

            if (parsedData && typeof parsedData.imagePrompt === 'string' && parsedData.imagePrompt.trim()) {
                uiData = parsedData;
                break; // Success
            } else {
                console.warn(`Attempt ${attempt} failed: Invalid UI screen data.`, parsedData);
            }
        } catch (error) {
            console.error(`Attempt ${attempt} failed with error:`, error);
        }

        if (attempt < maxRetries) {
            console.log(`Retrying UI screen generation... (${attempt}/${maxRetries})`);
        }
    }

    if (!uiData) {
        console.error("Failed to generate valid UI screen data after all retries.");
        throw new Error("A resposta do modelo para a tela de UI veio incompleta, mesmo após tentar novamente.");
    }

    const finalImagePrompt = `Mobile app UI screen design, high fidelity, HQ, 4k. ${uiData.imagePrompt}`;

    const imageResponse = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: finalImagePrompt,
        config: {
          numberOfImages: 1,
          aspectRatio: "9:16",
        }
    });

    const base64Image = imageResponse.generatedImages[0].image.imageBytes;
    const imageUrl = `data:image/png;base64,${base64Image}`;

    return { text: "Aqui está uma proposta de UI para a tela solicitada, baseada em todo o contexto do projeto.", imageUrl };
};

export const generateArtifact = async (artifactType: ArtifactType, context: string): Promise<GeneratedArtifact> => {
    switch (artifactType) {
        case ArtifactType.Observation:
            return getObservationSummary(context);
        case ArtifactType.InterviewQuestions:
            return getInterviewQuestions(context);
        case ArtifactType.SummarizeInterview:
            return getInterviewSummary(context);
        case ArtifactType.MOTables:
            return getMOTables(context);
        case ArtifactType.Personas:
            return getPersona(context);
        case ArtifactType.AgentModel:
            return getAgentModel(context);
        case ArtifactType.EmpathyMap:
            return getEmpathyMap(context);
        case ArtifactType.UserJourney:
            return getUserJourney(context);
        case ArtifactType.HypothesisGeneration:
            return getHypotheses(context);
        case ArtifactType.TaskModel:
            return getTaskModel(context);
        case ArtifactType.UserFlows:
            return getUserFlows(context);
        case ArtifactType.UIScreens:
            return getUIScreens(context);
        default:
            throw new Error('Tipo de artefato desconhecido');
    }
};

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { ArtifactType, Message, GeneratedArtifact } from './types';
import { generateArtifact, suggestPersonasFromContext } from './services/geminiService';
import OptionSelector from './components/OptionSelector';
import InputForm from './components/InputForm';
import ArtifactDisplay from './components/ArtifactDisplay';
import LoadingSpinner from './components/LoadingSpinner';
import ChatMessage from './components/ChatMessage';
import AdditionalInfoForm from './components/AdditionalInfoForm';
import DownloadOptions from './components/DownloadOptions';
import HypothesisEditor from './components/HypothesisEditor';

const App: React.FC = () => {
    const [messages, setMessages] = useState<Message[]>([]);
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [projectContext, setProjectContext] = useState<string>('');
    const [completedArtifacts, setCompletedArtifacts] = useState<ArtifactType[]>([]);
    const [currentArtifactType, setCurrentArtifactType] = useState<ArtifactType | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const handleOptionSelectRef = useRef<((type: ArtifactType) => void) | null>(null);

    // Refs for special flows (Agent Model and MO Tables)
    const handleAgentModelTriggerRef = useRef<() => void>(null);
    const handleMOTablesTriggerRef = useRef<() => void>(null);
    const handleMainMenuTriggerRef = useRef<() => void>(null);
    const handleTaskModelTriggerRef = useRef<() => void>(null);
    const handleHypothesisRefinementRef = useRef<((content: string) => void) | null>(null);

    // Ref to hold the latest state to avoid stale closures in callbacks
    const stateRef = useRef({ projectContext, completedArtifacts, currentArtifactType });
    useEffect(() => {
        stateRef.current = { projectContext, completedArtifacts, currentArtifactType };
    });

    const addMessage = useCallback((sender: 'bot' | 'user', content: React.ReactNode): string => {
        const id = `${Date.now()}-${Math.random()}`;
        setMessages(prev => [...prev, { id, sender, content }]);
        return id;
    }, []);

    const updateMessage = useCallback((id: string, content: React.ReactNode) => {
        setMessages(prev => prev.map(m => m.id === id ? { ...m, content } : m));
    }, []);

    const showMainMenu = useCallback((customText?: string) => {
        addMessage('bot', 
            <>
                <p className="mb-4 text-gray-200">{customText || "O que você gostaria de fazer agora?"}</p>
                <OptionSelector 
                    onSelect={(type) => handleOptionSelectRef.current?.(type)} 
                    completedArtifacts={stateRef.current.completedArtifacts} 
                />
            </>
        );
    }, [addMessage]);

    const initialBotMessage = useCallback(() => {
         addMessage('bot', 
            <>
                <p className="mb-4 text-gray-200">Olá! Sou seu assistente de UX. Como posso ajudar a iniciar seu projeto?</p>
                <OptionSelector onSelect={(type) => handleOptionSelectRef.current?.(type)} completedArtifacts={[]} />
            </>
        );
    }, [addMessage]);

    useEffect(() => {
       initialBotMessage();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [initialBotMessage]);

    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [messages]);

    const handleHypothesisFinalized = useCallback((finalContent: string) => {
        // Update context with final content
        const artifactType = ArtifactType.HypothesisGeneration;

        // Remove old hypothesis block from context if it exists (basic replacement logic)
        // Ideally we append, but for context cleanliness we update state.
        // For simplicity in this flow, we append the final version as the authoritative one.
        setProjectContext(prev => `${prev}\n\n--- HIPÓTESES DEFINIDAS (FINAL) ---\n${finalContent}`);

        addMessage('bot', 
            <>
                <p className="text-sm text-gray-400 mb-2">Hipóteses confirmadas. Deseja salvar este artefato?</p>
                <DownloadOptions artifactName={artifactType} content={finalContent} />

                <div className="flex flex-col gap-4 bg-zinc-900/40 backdrop-blur-md p-6 rounded-2xl border border-white/10 mt-6 shadow-xl">
                    <div>
                        <p className="mb-2 font-medium text-white">Próximo passo recomendado</p>
                        <p className="text-sm text-gray-400 mb-4 leading-relaxed">
                            Agora que as funcionalidades foram definidas, podemos detalhar o <strong className="text-sky-400">Modelo de Tarefas (CommonKADS MT1)</strong> para cada módulo identificado.
                        </p>
                        <p className="font-semibold text-orange-400">Deseja gerar o Modelo de Tarefas agora?</p>
                    </div>
                    <div className="flex flex-wrap gap-3 mt-2">
                        <button 
                            onClick={() => handleTaskModelTriggerRef.current?.()}
                            className="px-6 py-2.5 bg-gradient-to-r from-orange-600 to-amber-600 text-white rounded-xl hover:from-orange-500 hover:to-amber-500 transition-all duration-300 shadow-lg shadow-orange-900/20 font-medium flex-1 sm:flex-none border border-white/10"
                        >
                            Sim, gerar MT1
                        </button>
                        <button 
                            onClick={() => handleMainMenuTriggerRef.current?.()}
                            className="px-6 py-2.5 bg-zinc-800/50 hover:bg-zinc-700/50 text-gray-300 rounded-xl transition-all duration-300 flex-1 sm:flex-none border border-white/5 backdrop-blur-sm"
                        >
                            Não, ver outras opções
                        </button>
                    </div>
                </div>
            </>
        );
    }, [addMessage]);

    useEffect(() => {
        handleHypothesisRefinementRef.current = handleHypothesisFinalized;
    }, [handleHypothesisFinalized]);

    const handleGeneration = useCallback(async (artifactType: ArtifactType, context: string, isPrimaryInput: boolean) => {
        setIsLoading(true);
        const loadingMessageId = addMessage('bot', <LoadingSpinner />);
        try {
            const result: GeneratedArtifact = await generateArtifact(artifactType, context);

            // CRITICAL FIX: Remove Base64 images from the context text before saving to state.
            // This prevents the "token limit exceeded" error when sending history back to Gemini.
            // We replace the image syntax ![Alt](data:...) with a placeholder [Imagem: Alt].
            const textWithoutImages = result.text.replace(/!\[(.*?)\]\(data:image\/.*?;base64,.*?\)/g, '\n> [Imagem Gerada: $1]\n');

            if (isPrimaryInput) {
                 setProjectContext(`## ${artifactType}\n\n${textWithoutImages}`);
            } else {
                 setProjectContext(prev => `${prev}\n\n---\n\n## ${artifactType}\n\n${textWithoutImages}`);
            }

            const newCompletedArtifacts = [...stateRef.current.completedArtifacts, artifactType];
            setCompletedArtifacts(newCompletedArtifacts);

            // SPECIAL HANDLING FOR HYPOTHESIS GENERATION
            if (artifactType === ArtifactType.HypothesisGeneration) {
                updateMessage(loadingMessageId, 
                    <HypothesisEditor 
                        initialContent={result.text} 
                        onSave={(content) => handleHypothesisRefinementRef.current?.(content)} 
                    />
                );
                // We STOP here for Hypothesis. The flow continues inside handleHypothesisFinalized via onSave.
                return;
            }

            updateMessage(loadingMessageId, <ArtifactDisplay artifact={result} />);

            // Add Download Options (Standard Flow)
            // Exclude Download Options for User Flows (User Request)
            if (artifactType !== ArtifactType.UserFlows) {
                addMessage('bot', 
                    <>
                        <p className="text-sm text-gray-400 mb-2">Deseja salvar este artefato?</p>
                        <DownloadOptions artifactName={artifactType} content={result.text} />
                    </>
                );
            }

            // Flow Control based on Artifact Type
            if (artifactType === ArtifactType.Personas) {
                // Fluxo específico para sugerir o Modelo de Agentes (CommonKADS)
                addMessage('bot', 
                    <div className="flex flex-col gap-4 bg-zinc-900/40 backdrop-blur-md p-6 rounded-2xl border border-white/10 mt-2 shadow-xl">
                        <div>
                            <p className="mb-2 font-medium text-white">Personas geradas com sucesso!</p>
                            <p className="text-sm text-gray-400 mb-4 leading-relaxed">
                                Uma prática recomendada é estruturar esses papéis usando o <strong className="text-sky-400">Modelo de Agentes (CommonKADS)</strong> para definir responsabilidades, comunicação e restrições.
                            </p>
                            <p className="font-semibold text-orange-400">Deseja gerar o Modelo de Agentes para as personas acima?</p>
                        </div>
                        <div className="flex flex-wrap gap-3 mt-2">
                            <button 
                                onClick={() => handleAgentModelTriggerRef.current?.()}
                                className="px-6 py-2.5 bg-gradient-to-r from-orange-600 to-amber-600 text-white rounded-xl hover:from-orange-500 hover:to-amber-500 transition-all duration-300 shadow-lg shadow-orange-900/20 font-medium flex-1 sm:flex-none border border-white/10"
                            >
                                Sim, gerar Modelo
                            </button>
                            <button 
                                onClick={() => handleMainMenuTriggerRef.current?.()}
                                className="px-6 py-2.5 bg-zinc-800/50 hover:bg-zinc-700/50 text-gray-300 rounded-xl transition-all duration-300 flex-1 sm:flex-none border border-white/5 backdrop-blur-sm"
                            >
                                Não, ver outras opções
                            </button>
                        </div>
                    </div>
                );
            } else if (artifactType === ArtifactType.SummarizeInterview) {
                // Fluxo específico para sugerir Tabelas MO (CommonKADS)
                addMessage('bot', 
                    <div className="flex flex-col gap-4 bg-zinc-900/40 backdrop-blur-md p-6 rounded-2xl border border-white/10 mt-2 shadow-xl">
                        <div>
                            <p className="mb-2 font-medium text-white">Resumo da entrevista concluído!</p>
                            <p className="text-sm text-gray-400 mb-4 leading-relaxed">
                                Com base nos problemas identificados, podemos criar as <strong className="text-sky-400">Tabelas MO1 (Contexto)</strong> e <strong className="text-sky-400">MO5 (Viabilidade)</strong> do Modelo Organizacional (CommonKADS).
                            </p>
                            <p className="font-semibold text-orange-400">Deseja criar as Tabelas MO agora?</p>
                        </div>
                        <div className="flex flex-wrap gap-3 mt-2">
                            <button 
                                onClick={() => handleMOTablesTriggerRef.current?.()}
                                className="px-6 py-2.5 bg-gradient-to-r from-orange-600 to-amber-600 text-white rounded-xl hover:from-orange-500 hover:to-amber-500 transition-all duration-300 shadow-lg shadow-orange-900/20 font-medium flex-1 sm:flex-none border border-white/10"
                            >
                                Sim, criar Tabelas MO
                            </button>
                            <button 
                                onClick={() => handleMainMenuTriggerRef.current?.()}
                                className="px-6 py-2.5 bg-zinc-800/50 hover:bg-zinc-700/50 text-gray-300 rounded-xl transition-all duration-300 flex-1 sm:flex-none border border-white/5 backdrop-blur-sm"
                            >
                                Não, ver outras opções
                            </button>
                        </div>
                    </div>
                );
            } else {
                // Fluxo padrão
                addMessage('bot', 
                    <>
                        <p className="mb-4 text-gray-200">Excelente! O que você gostaria de fazer agora?</p>
                        <OptionSelector onSelect={(type) => handleOptionSelectRef.current?.(type)} completedArtifacts={newCompletedArtifacts} />
                    </>
                );
            }

        } catch (error) {
            console.error('Error generating artifact:', error);
            updateMessage(loadingMessageId, <p className="text-rose-400">Desculpe, ocorreu um erro ao gerar o artefato. Isso pode ocorrer se o contexto estiver muito longo ou se houver instabilidade na API. Tente simplificar a solicitação.</p>);
            showMainMenu("Ocorreu um erro. O que você gostaria de fazer agora?");
        } finally {
            setIsLoading(false);
        }
    }, [addMessage, updateMessage, showMainMenu]);

    // Implementação dos handlers via refs para evitar dependências circulares/stale closures nos botões renderizados
    useEffect(() => {
        handleAgentModelTriggerRef.current = () => {
            addMessage('user', "Sim, gerar Modelo de Agentes");
            handleGeneration(ArtifactType.AgentModel, stateRef.current.projectContext, false);
        };

        handleMOTablesTriggerRef.current = () => {
            addMessage('user', "Sim, criar as Tabelas MO");
            handleGeneration(ArtifactType.MOTables, stateRef.current.projectContext, false);
        };

        handleTaskModelTriggerRef.current = () => {
            addMessage('user', "Sim, gerar Modelo de Tarefas (MT1)");
            handleGeneration(ArtifactType.TaskModel, stateRef.current.projectContext, false);
        };

        handleMainMenuTriggerRef.current = () => {
             addMessage('user', "Não, obrigado.");
             showMainMenu("Tudo bem! O que mais você deseja criar?");
        };
    }, [addMessage, handleGeneration, showMainMenu]);

    const handleInputSubmit = useCallback((context: string) => {
        const artifactType = stateRef.current.currentArtifactType;
        if (!artifactType) return;

        const contextToShow = context.length > 300 ? `${context.substring(0, 300)}...` : context;
        addMessage('user', <pre className="whitespace-pre-wrap font-sans text-gray-300">{contextToShow}</pre>);

        handleGeneration(artifactType, context, true);
    }, [addMessage, handleGeneration]);

    const handleAdditionalInfoSubmit = useCallback((additionalContext: string) => {
        const artifactType = stateRef.current.currentArtifactType;
        if (!artifactType) return;

        if(additionalContext) {
            const contextToShow = additionalContext.length > 300 ? `${additionalContext.substring(0, 300)}...` : additionalContext;
            addMessage('user', <pre className="whitespace-pre-wrap font-sans text-gray-300">{contextToShow}</pre>);
        } else {
            addMessage('user', "(Nenhuma informação adicional)");
        }

        const fullContext = `${stateRef.current.projectContext}\n\n--- INFORMAÇÕES ADICIONAIS DO USUÁRIO ---\n${additionalContext}`;
        handleGeneration(artifactType, fullContext.trim(), false);

    }, [addMessage, handleGeneration]);

    const handleOptionSelect = useCallback(async (type: ArtifactType) => {
        setCurrentArtifactType(type);
        addMessage('user', `Eu escolho: ${type}`);

        const { projectContext } = stateRef.current;

        // Special handling for Personas when context exists
        if (type === ArtifactType.Personas && projectContext) {
            setIsLoading(true);
            const loadingId = addMessage('bot', <LoadingSpinner />);

            try {
                // Analyze context to find suggested personas
                const suggestions = await suggestPersonasFromContext(projectContext);

                let suggestionMessage = "";
                if (suggestions.length > 0) {
                    const names = suggestions.join(', ');
                    suggestionMessage = `Com base no contexto anterior, identifiquei que devem ser observadas as necessidades de ${suggestions.length > 1 ? 'destas personas' : 'desta persona'}: **${names}**.`;
                } else {
                    suggestionMessage = "Analisei o contexto, mas não identifiquei papéis explícitos, porém podemos criar personas baseadas nos dados gerais.";
                }

                updateMessage(loadingId, <p className="text-gray-200">{suggestionMessage}</p>);

                // Define a specific submit handler for this step that includes the suggestions
                const handlePersonaSubmit = (additionalInput: string) => {
                    if(additionalInput) {
                        const contextToShow = additionalInput.length > 300 ? `${additionalInput.substring(0, 300)}...` : additionalInput;
                        addMessage('user', <pre className="whitespace-pre-wrap font-sans text-gray-300">{contextToShow}</pre>);
                    } else {
                        addMessage('user', "(Sem adicionar mais personas)");
                    }

                    const combinedContext = `
                        ${stateRef.current.projectContext}

                        --- DIRECIONAMENTO DE PERSONAS ---
                        Personas Sugeridas pelo Sistema: ${suggestions.join(', ')}
                        Solicitação Adicional do Usuário: ${additionalInput}
                    `.trim();

                    handleGeneration(ArtifactType.Personas, combinedContext, false);
                };

                // Show the form asking if user wants to add more
                addMessage('bot', 
                    <AdditionalInfoForm 
                        artifactType={type} 
                        onSubmit={handlePersonaSubmit} 
                        isLoading={false}
                        customLabel="Deseja incluir mais alguma persona para geração? Se sim, digite abaixo (ex: 'Também inclua um Gerente de Loja'). Caso contrário, apenas clique em Gerar."
                    />
                );

            } catch (error) {
                console.error("Error suggesting personas:", error);
                // Fallback to normal flow if suggestion fails
                 addMessage('bot', <AdditionalInfoForm artifactType={type} onSubmit={handleAdditionalInfoSubmit} isLoading={false} />);
            } finally {
                setIsLoading(false);
            }
            return;
        }

        // Standard flow for other artifacts or empty context
        if (!projectContext) {
             addMessage('bot', <InputForm artifactType={type} onSubmit={handleInputSubmit} isLoading={isLoading} />);
        } else {
            addMessage('bot', <AdditionalInfoForm artifactType={type} onSubmit={handleAdditionalInfoSubmit} isLoading={isLoading} />);
        }
    }, [isLoading, addMessage, handleInputSubmit, handleAdditionalInfoSubmit, handleGeneration, updateMessage]);

    useEffect(() => {
        handleOptionSelectRef.current = handleOptionSelect;
    }, [handleOptionSelect]);

    return (
        <div className="flex flex-col h-screen text-[#EFEFEF] font-sans relative overflow-hidden">
            {/* Ambient Background */}
            <div className="fixed inset-0 bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-zinc-800 via-zinc-950 to-zinc-950 -z-10"></div>

            <header className="fixed top-0 left-0 right-0 z-50 h-20 transition-all duration-300">
                {/* Modern Gradient Background with Blur */}
                <div className="absolute inset-0 bg-gradient-to-r from-zinc-900 via-[#1a1a1a] to-zinc-900 opacity-95 backdrop-blur-xl"></div>

                {/* Glowing Bottom Line */}
                <div className="absolute bottom-0 left-0 right-0 h-[1px] bg-gradient-to-r from-transparent via-orange-500/50 to-transparent shadow-[0_0_15px_rgba(249,115,22,0.5)]"></div>

                <div className="relative h-full w-full flex items-center justify-center px-4">
                     <div className="flex flex-col items-center justify-center z-10">
                        <h1 className="text-lg md:text-xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-gray-100 via-white to-gray-300 tracking-tight text-center leading-tight">
                            Agentes de Engenharia do Conhecimento
                        </h1>
                        <span className="text-xs font-medium text-orange-400/90 tracking-wide uppercase mt-1 text-center">
                            Centrados no Usuário
                        </span>
                     </div>
                </div>
            </header>

            <main className="flex-1 overflow-y-auto p-4 pt-28 pb-8 scroll-smooth">
                <div className="max-w-4xl mx-auto space-y-8">
                    {messages.map((msg) => (
                        <ChatMessage key={msg.id} sender={msg.sender}>
                            {msg.content}
                        </ChatMessage>
                    ))}
                    <div ref={messagesEndRef} />
                </div>
            </main>
        </div>
    );
};

