import React, { useEffect, useRef } from 'react';
import { GeneratedArtifact } from '../types';

declare global {
    interface Window {
        mermaid?: {
            run: (options: { nodes: Array<Element> }) => void;
        }
    }
}

interface ArtifactDisplayProps {
    artifact: GeneratedArtifact;
}

const ArtifactDisplay: React.FC<ArtifactDisplayProps> = ({ artifact }) => {
    const mermaidRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (window.mermaid && mermaidRef.current) {
            // Find all mermaid divs within this component
            const nodes = Array.from(mermaidRef.current.querySelectorAll('.mermaid')) as Element[];
            if (nodes.length > 0) {
                 // Reset them for re-rendering if needed (remove data-processed attribute)
                 nodes.forEach(node => node.removeAttribute('data-processed'));

                 // Run mermaid on all found nodes
                 window.mermaid.run({ nodes: nodes });
            }
        }
    }, [artifact]);

    // Helper function to download mermaid SVG as PNG
    const downloadMermaidAsPng = (containerId: string, filename: string) => {
        const container = document.getElementById(containerId);
        if (!container) return;

        const svg = container.querySelector('svg');
        if (!svg) {
            alert('Erro: O diagrama ainda não foi renderizado completamente. Tente novamente em alguns instantes.');
            return;
        }

        const serializer = new XMLSerializer();
        const source = serializer.serializeToString(svg);

        // Add namespaces
        if (!source.match(/^<svg[^>]+xmlns="http\:\/\/www\.w3\.org\/2000\/svg"/)) {
            source.replace(/^<svg/, '<svg xmlns="http://www.w3.org/2000/svg"');
        }
        if (!source.match(/^<svg[^>]+xmlns:xlink/)) {
            source.replace(/^<svg/, '<svg xmlns:xlink="http://www.w3.org/1999/xlink"');
        }

        const img = new Image();
        const svgBlob = new Blob([source], { type: 'image/svg+xml;charset=utf-8' });
        const url = URL.createObjectURL(svgBlob);

        img.onload = function () {
            const canvas = document.createElement('canvas');
            // Scale up for better quality
            const scale = 2; 
            canvas.width = (svg.getBoundingClientRect().width || 800) * scale;
            canvas.height = (svg.getBoundingClientRect().height || 600) * scale;

            const ctx = canvas.getContext('2d');
            if (ctx) {
                // Background color (Mermaid dark theme is transparent by default mostly, add dark bg)
                ctx.fillStyle = "#18181b"; // zinc-900
                ctx.fillRect(0, 0, canvas.width, canvas.height);
                ctx.scale(scale, scale);
                ctx.drawImage(img, 0, 0);

                const imgURI = canvas.toDataURL('image/png');

                const evt = new MouseEvent('click', {
                    view: window,
                    bubbles: false,
                    cancelable: true
                });

                const a = document.createElement('a');
                a.setAttribute('download', `${filename}.png`);
                a.setAttribute('href', imgURI);
                a.setAttribute('target', '_blank');
                a.dispatchEvent(evt);
            }
            URL.revokeObjectURL(url);
        };
        img.src = url;
    };

    // Case 0: Multiple Artifacts (e.g. User Flows per module)
    if (artifact.multiArtifacts && artifact.multiArtifacts.length > 0) {
        return (
            <div ref={mermaidRef} className="space-y-8">
                 <div className="text-xs font-bold text-sky-400 uppercase mb-2 tracking-wider ml-1">
                    Fluxos Gerados ({artifact.multiArtifacts.length})
                </div>
                {artifact.multiArtifacts.map((sub, index) => {
                    const uniqueId = `mermaid-multi-${index}-${Date.now()}`;
                    return (
                        <div key={index} className="bg-zinc-900/60 backdrop-blur-md p-6 rounded-xl border border-white/10 shadow-inner group">
                            <div className="flex justify-between items-center mb-4 border-b border-white/5 pb-2">
                                <h4 className="text-sm font-bold text-white">{sub.title}</h4>
                                {sub.type === 'mermaid' && (
                                    <button 
                                        onClick={() => downloadMermaidAsPng(uniqueId, sub.title.replace(/\s+/g, '_'))}
                                        className="text-xs px-3 py-1.5 rounded-lg bg-sky-500/10 text-sky-400 hover:bg-sky-500/20 border border-sky-500/30 transition-colors"
                                    >
                                        Baixar Imagem
                                    </button>
                                )}
                            </div>

                            {sub.type === 'mermaid' ? (
                                <div id={uniqueId}>
                                    <pre className="mermaid language-mermaid text-center overflow-x-auto">
                                        {sub.content}
                                    </pre>
                                </div>
                            ) : (
                                <div className="whitespace-pre-wrap text-sm text-gray-300">{sub.content}</div>
                            )}
                        </div>
                    );
                })}
            </div>
        );
    }

    // Case 1: Single Mermaid Diagram
    if (artifact.isMermaid) {
        const uniqueId = `mermaid-single-${Date.now()}`;
        return (
            <div ref={mermaidRef}>
                <div className="flex justify-between items-end mb-2">
                    <div className="text-xs font-bold text-sky-400 uppercase tracking-wider ml-1">
                        Diagrama Gerado
                    </div>
                    <button 
                        onClick={() => downloadMermaidAsPng(uniqueId, 'diagrama_fluxo')}
                        className="text-xs px-3 py-1.5 rounded-lg bg-sky-500/10 text-sky-400 hover:bg-sky-500/20 border border-sky-500/30 transition-colors"
                    >
                        Baixar Imagem (PNG)
                    </button>
                </div>
                <div id={uniqueId} className="bg-zinc-900/60 backdrop-blur-md p-6 rounded-xl border border-white/10 shadow-inner overflow-x-auto">
                    <pre className="mermaid language-mermaid text-center">
                        {artifact.text}
                    </pre>
                </div>
            </div>
        );
    }

    // Case 2: UI Screens (Keep Visual Image, Truncate Text)
    if (artifact.imageUrl) {
         return (
            <div className="space-y-4">
                 <div className="text-xs font-bold text-violet-400 uppercase mb-2 tracking-wider ml-1">
                    Interface Gerada
                </div>
                <div className={`flex justify-center w-full`}>
                    <div className={`relative rounded-xl overflow-hidden shadow-2xl border-4 border-zinc-800/50 w-full max-w-sm`}>
                        <img
                            src={artifact.imageUrl}
                            alt="Artefato Gerado"
                            className="w-full h-full object-cover"
                        />
                         <div className="absolute inset-0 shadow-[inset_0_0_20px_rgba(0,0,0,0.5)] pointer-events-none"></div>
                    </div>
                </div>
                 <div className="prose prose-invert prose-sm max-w-none bg-zinc-950/40 backdrop-blur-sm p-4 rounded-xl border border-white/5 shadow-inner opacity-80">
                    <p className="text-xs text-gray-400 mb-1 font-bold uppercase">Resumo do Prompt:</p>
                    <div className="whitespace-pre-wrap font-sans text-gray-300 leading-relaxed text-sm line-clamp-3">
                         {artifact.text}
                    </div>
                </div>
            </div>
         )
    }

    // Case 3: Text Artifacts (Personas, Observations, Reports, etc.)

    // Remove markdown image syntax `![alt](url)` to avoid raw base64 mess in summary
    // and replace with a placeholder.
    const textWithoutImages = artifact.text.replace(/!\[(.*?)\]\(.*?\)/g, ' [Imagem disponível no PDF] ');

    const PREVIEW_LIMIT = 300;
    const isLong = textWithoutImages.length > PREVIEW_LIMIT;
    const summaryText = isLong 
        ? textWithoutImages.substring(0, PREVIEW_LIMIT).trim() + "..." 
        : textWithoutImages;

    return (
        <div className="space-y-3">
            <div className="text-xs font-bold text-orange-400 uppercase tracking-wider ml-1">
                Resumo do Resultado
            </div>
            <div className="prose prose-invert prose-sm sm:prose-base max-w-none bg-zinc-950/40 backdrop-blur-sm p-6 rounded-2xl border border-white/5 shadow-inner relative overflow-hidden">
                <div className="whitespace-pre-wrap font-sans text-gray-200 leading-relaxed">
                    {summaryText}
                </div>

                {/* Visual fade effect for truncated text */}
                {isLong && (
                    <div className="absolute bottom-0 left-0 right-0 h-16 bg-gradient-to-t from-zinc-900/90 to-transparent pointer-events-none"></div>
                )}
            </div>

            {isLong && (
                 <div className="flex items-center justify-center gap-2 text-xs text-gray-500 italic mt-1">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                    <span>O artefato completo (com imagens e formatação) está disponível nos botões de download abaixo.</span>
                </div>
            )}
        </div>
    );
};

