const getUserJourney = async (context: string): Promise<GeneratedArtifact> => {
    // 1. Identify ALL Personas from the context
    // Priority: Try to use Gemini to extract JSON
    const identificationPrompt = `
    Analise o texto completo abaixo buscando identificar TODAS as Personas definidas.

    Geralmente elas aparecem como Títulos (H1 ou H2) seguidos de descrições ou blocos com "# Nome".
    Procure por: "# Nome: Papel", "# Nome - Papel", "# Nome" ou listas de personas geradas anteriormente.

    Seu objetivo é listar TODOS os perfis encontrados, não apenas um.

    Retorne EXCLUSIVAMENTE um JSON com a lista de todas as personas encontradas:
    [
        { "name": "Nome identificado", "role": "Papel ou Profissão identificada" }
    ]

    Contexto:
    ${context}
    `;

    let targets: { name: string; role: string }[] = [];
    try {
        const idResponse = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: identificationPrompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: { name: { type: Type.STRING }, role: { type: Type.STRING } }
                    }
                }
            }
        });
        const parsed = safeParseJson(idResponse.text);
        if (parsed) targets = parsed;
    } catch (e) {
        console.warn("Failed to parse personas for journey via JSON, attempting fallback.");
    }

    // 2. Fallback: Regex extraction if JSON failed or returned nothing
    // This looks for lines starting with '#' that are NOT known artifact headers.
    if (targets.length === 0) {
        const headerRegex = /^#\s+(.+)$/gm;
        let match;

        const knownArtifactHeaders = [
            "Resumir Observação", "Gerar Perguntas", "Resumir Entrevista", 
            "Modelo Organizacional", "Criar Personas", "Gerar Modelo", 
            "Gerar Mapa", "Jornada do Usuário", "Geração de Hipóteses", 
            "Desenhar Fluxos", "Geração de Telas", "Mapas de Empatia", 
            "Tabela MO1", "Tabela MO5", "Observação", "Entrevista", "Relatório"
        ];

        while ((match = headerRegex.exec(context)) !== null) {
            const headerText = match[1].trim();
            // Check if it's a known artifact header (approximate match)
            const isKnown = knownArtifactHeaders.some(k => headerText.includes(k));

            // Personas usually have short headers (< 60 chars) and aren't system headers
            if (!isKnown && headerText.length < 60) { 
                // Try to split Name: Role if present
                const parts = headerText.split(/[:|-]/);
                const name = parts[0].trim();
                const role = parts.length > 1 ? parts[1].trim() : "Usuário Identificado";

                // Avoid duplicates
                if (!targets.some(t => t.name === name)) {
                    targets.push({ name, role });
                }
            }
        }
    }

    // 3. Final Fallback if truly nothing found
    if (targets.length === 0) {
        targets.push({ name: "Usuário Padrão", role: "Principal" });
    }

    let fullMarkdown = "";

    // 4. Generate Journey for each identified persona
    for (const target of targets) {
        const prompt = `Atue como um UX Designer Especialista.
        Crie uma Jornada do Usuário (User Journey Map) baseada no framework de Gibbons (2018) EXCLUSIVAMENTE para a persona: **${target.name}** (${target.role}).

        INSTRUÇÃO DE ESCRITA:
        Escreva uma jornada que represente o dia a dia desse perfil específico.
        **IMPORTANTE**: A narrativa deve ser IMPESSOAL e GENÉRICA. 
        - NÃO use o nome "${target.name}" no texto das etapas.
        - Use termos como "O usuário", "O ${target.role}", "O cliente".
        - O objetivo é que a jornada sirva para qualquer pessoa que se encaixe nesse arquétipo.
        - NÃO USE TAGS HTML (sem <br>, <b>, etc). Use apenas Markdown.
        - NÃO INCLUA textos de introdução ou conclusão (Ex: "Com certeza", "Aqui está a jornada", "Espero que ajude"). Comece direto pelo Cenário.

        FORMATO OBRIGATÓRIO (MARKDOWN PURO):

        ### 1. Cenário
        (Descreva o contexto e o objetivo para este perfil específico)

        ### 2. Ações
        (Lista numerada das ações. Ex: 1. O usuário abre o app...)

        ### 3. Oportunidades
        (Lista de melhorias possíveis)

        ### 4. Serviços Externos
        (Ferramentas ou pessoas envolvidas)

        Contexto do Projeto:
        ${context}
        `;

        try {
            const response = await ai.models.generateContent({
                model: "gemini-2.5-pro",
                contents: prompt
            });

            // Clean any potential HTML
            const cleanText = response.text.replace(/<[^>]*>?/gm, '');

            // Prioritize Role/Archetype for the header to keep it impersonal.
            // Fallback to name only if role is missing or generic placeholder.
            let journeyTitle = target.role;
            if (!journeyTitle || journeyTitle.length < 3 || journeyTitle === 'Principal' || journeyTitle === 'Usuário Identificado' || journeyTitle === 'Usuário Padrão') {
                journeyTitle = target.name;
            }

            fullMarkdown += `## Jornada: ${journeyTitle}\n\n${cleanText}\n\n---\n\n`;
        } catch (err) {
            console.error(`Error generating journey for ${target.name}`, err);
            fullMarkdown += `## Jornada: ${target.name}\n\n*Erro ao gerar jornada para esta persona.*\n\n---\n\n`;
        }
    }

    return { text: fullMarkdown };
};

const getHypotheses = async (context: string): Promise<GeneratedArtifact> => {
    const prompt = `Atue como um Product Manager e Arquiteto de Soluções.
    Com base no contexto do projeto (Personas, Jornadas, Dores), gere uma Árvore de Funcionalidades (Feature Tree) organizada por Módulos.

    INSTRUÇÃO:
    - Analise o contexto para entender o escopo do sistema.
    - Divida o sistema em Grandes Módulos (ex: Autenticação, Perfil, Gestão de X, Relatórios).
    - Para cada módulo, liste as Funcionalidades Principais como marcadores.
    - Para cada funcionalidade, liste Sub-funcionalidades (detalhes) usando indentação (tabulação).

    REGRAS DE FORMATAÇÃO:
    - Use Markdown com listas aninhadas.
    - NÃO INCLUA TEXTO DE INTRODUÇÃO. Comece direto pelos módulos.

    Exemplo de formato esperado:

    ### Módulo: [Nome do Módulo]
    *   **[Nome da Funcionalidade Principal]**
        *   [Sub-funcionalidade ou detalhe]
        *   [Sub-funcionalidade ou detalhe]
    *   **[Nome da Funcionalidade Principal]**
        *   [Detalhe]

    Contexto do Projeto:
    ${context}`;

    const response = await ai.models.generateContent({
        model: "gemini-2.5-pro",
        contents: prompt
    });

    return { text: response.text };
};

const getTaskModel = async (context: string): Promise<GeneratedArtifact> => {
    const prompt = `Atue como um Engenheiro do Conhecimento especialista em CommonKADS (Schreiber, 2000).

    TAREFA: Analise os Módulos definidos na etapa anterior de "Geração de Hipóteses" e crie o Modelo de Tarefas (Task Model - MT1) para CADA módulo.

    INSTRUÇÃO:
    - Identifique cada "Módulo" principal gerado na árvore de funcionalidades (no contexto).
    - Para CADA Módulo, gere um documento estruturado "MT1" completo.
    - Use EXATAMENTE as chaves em negrito listadas abaixo.

    FORMATO DE SAÍDA (Repita para cada módulo):

    ## Tarefa: [Nome do Módulo]

    **Objetivos e valor:** (Descreva o objetivo e valor que o módulo agregará para o usuário)

    **Dependência e fluxos:** (O que deve ser feito antes/entrada e depois/saída da funcionalidade)

    **Objetos manipulados:** (Documentos, arquivos, planilhas, dados inseridos como entrada, elementos finalizados como saída)

    **Tempo e controle:** (Frequência, pré-condição, pós-condição e restrições)

    **Agentes:** (Quais personas do contexto estão envolvidas)

    **Conhecimento e competência:** (Quais conhecimentos técnicos/específicos o agente precisa ter para realizar a tarefa)

    **Recursos:** (Estimativa de tempo médio gasto pelo colaborador/agente ao trabalhar nesta tarefa)

    **Qualidade e desempenho:** (Critérios de qualidade para considerar a tarefa bem sucedida)

    ---

    REGRAS:
    - NÃO inclua introduções.
    - Use Markdown.
    - O conteúdo deve ser detalhado e baseado em todo o contexto do projeto armazenado (Personas, Jornadas, etc).

    Contexto do Projeto:
    ${context}`;

    const response = await ai.models.generateContent({
        model: "gemini-2.5-pro",
        contents: prompt
    });

    return { text: response.text };
};

const getUserFlows = async (context: string): Promise<GeneratedArtifact> => {
    const prompt = `Atue como um Arquiteto de Informação. 

    TAREFA: Analise o contexto (especialmente a seção 'Geração de Hipóteses') e identifique TODOS os Módulos do sistema.
    Para CADA módulo encontrado, gere um Diagrama de Fluxo de Usuário (User Flow) usando sintaxe Mermaid.js.

    INSTRUÇÃO CRÍTICA DE SINTAXE:
    1. O código Mermaid DEVE começar explicitamente com "graph TD".
    2. OBRIGATÓRIO: Coloque TODO o texto dos nós entre aspas duplas. 
       Correto: A["Texto (detalhe)"] --> B["Outro texto"]
    3. PROIBIDO USAR PARENTESES CURVOS () DENTRO DO TEXTO DO NÓ. Use hifens ou colchetes se necessário.
       Correto: A["Login - Opcional"]
       Incorreto: A["Login (Opcional)"]
    4. PROIBIDO USAR TAGS HTML. Se precisar de quebra de linha, use \\n DENTRO das aspas.
    5. Use IDs de nós simples e sem caracteres especiais (ex: A, B, C, Start, End, Step1).
    6. **IMPORTANTE**: Mantenha o texto dos nós CURTO e CONCISO (máximo 4-5 palavras) para garantir que o diagrama fique legível.

    OUTPUT ESPERADO:
    Retorne APENAS um Array JSON contendo objetos com o título do módulo e o código Mermaid.
    NÃO coloque blocos de markdown (\`\`\`) dentro do valor da string JSON.

    Exemplo de formato JSON de retorno:
    [
        {
            "title": "Módulo de Autenticação",
            "code": "graph TD\\nStart[\\"Início\\"] --> Check{.\\"Possui conta?\\".}..."
        },
        {
            "title": "Módulo de Dashboard",
            "code": "graph TD\\n..."
        }
    ]

    Contexto Completo:
    ${context}`;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-pro",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            title: { type: Type.STRING },
                            code: { type: Type.STRING }
                        }
                    }
                }
            }
        });

        const parsed = safeParseJson(response.text);

        if (Array.isArray(parsed) && parsed.length > 0) {
            // Map the parsed JSON to the SubArtifact structure
            const artifacts = parsed.map((item: any) => {
                const cleanCode = cleanMermaidCode(item.code || "");
                return {
                    title: item.title,
                    content: cleanCode,
                    type: 'mermaid' as const
                };
            }).filter(a => a.content.length > 10); // Check length to be sure it has some content

            if (artifacts.length === 0) {
                 throw new Error("Nenhum diagrama válido encontrado no JSON.");
            }

            return { 
                text: "Fluxos de Usuário gerados para cada módulo identificado.", 
                multiArtifacts: artifacts 
            };
        } else {
            throw new Error("Formato inválido de resposta para fluxos.");
        }

    } catch (error) {
        console.error("Error generating user flows:", error);
        // Fallback to single text generation if JSON fails
        const fallbackPrompt = `Crie um único diagrama Mermaid graph TD abrangendo o fluxo principal do sistema descrito no contexto. NÃO USE HTML. Use apenas texto entre aspas. NÃO use parenteses dentro do texto.\n${context}`;
        const fallbackResponse = await ai.models.generateContent({ model: "gemini-2.5-pro", contents: fallbackPrompt});
        const mermaidCode = cleanMermaidCode(fallbackResponse.text);

        return { 
            text: mermaidCode, 
            isMermaid: true 
        };
    }
};

const getUIScreens = async (context: string): Promise<GeneratedArtifact> => {
    const uiPrompt = `Atue como um Diretor de Arte de UI Design. Sua tarefa é escrever um prompt de geração de imagem textual altamente detalhado para criar uma tela de interface de alta fidelidade.

Considere as personas, o fluxo e os requisitos.
A resposta DEVE ser um objeto JSON com o campo "imagePrompt".

O "imagePrompt" deve descrever a tela visualmente para um modelo de IA generativa (como Imagen ou Midjourney):
- Descreva o tipo de tela (ex: Dashboard, Login, Feed, Detalhe de Produto).
- Defina o estilo visual (ex: Neomorfismo, Material Design, Minimalista, Dark Mode, Cores vibrantes).
- Descreva elementos específicos: Tipografia (Sans-serif, bold headers), Botões (arredondados, gradiente), Ícones (outline, filled).
- Descreva o conteúdo fictício visível para tornar a tela realista.

Contexto do Projeto: ${context}`;

    let uiData;
    const maxRetries = 2;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
        try {
            const uiResponse = await ai.models.generateContent({
                model: "gemini-2.5-pro",
                contents: uiPrompt,
                config: {
                  responseMimeType: "application/json",
                  responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                      imagePrompt: { type: Type.STRING },
                    }
                  }
                }
            });

            const parsedData = safeParseJson(uiResponse.text);

            if (parsedData && typeof parsedData.imagePrompt === 'string' && parsedData.imagePrompt.trim()) {
                uiData = parsedData;
                break; // Success
            } else {
                console.warn(`Attempt ${attempt} failed: Invalid UI screen data.`, parsedData);
            }
        } catch (error) {
            console.error(`Attempt ${attempt} failed with error:`, error);
        }

        if (attempt < maxRetries) {
            console.log(`Retrying UI screen generation... (${attempt}/${maxRetries})`);
        }
    }

    if (!uiData) {
        console.error("Failed to generate valid UI screen data after all retries.");
        throw new Error("A resposta do modelo para a tela de UI veio incompleta, mesmo após tentar novamente.");
    }

    const finalImagePrompt = `Mobile app UI screen design, high fidelity, HQ, 4k. ${uiData.imagePrompt}`;

    const imageResponse = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: finalImagePrompt,
        config: {
          numberOfImages: 1,
          aspectRatio: "9:16",
        }
    });

    const base64Image = imageResponse.generatedImages[0].image.imageBytes;
    const imageUrl = `data:image/png;base64,${base64Image}`;

    return { text: "Aqui está uma proposta de UI para a tela solicitada, baseada em todo o contexto do projeto.", imageUrl };
};

export const generateArtifact = async (artifactType: ArtifactType, context: string): Promise<GeneratedArtifact> => {
    switch (artifactType) {
        case ArtifactType.Observation:
            return getObservationSummary(context);
        case ArtifactType.InterviewQuestions:
            return getInterviewQuestions(context);
        case ArtifactType.SummarizeInterview:
            return getInterviewSummary(context);
        case ArtifactType.MOTables:
            return getMOTables(context);
        case ArtifactType.Personas:
            return getPersona(context);
        case ArtifactType.AgentModel:
            return getAgentModel(context);
        case ArtifactType.EmpathyMap:
            return getEmpathyMap(context);
        case ArtifactType.UserJourney:
            return getUserJourney(context);
        case ArtifactType.HypothesisGeneration:
            return getHypotheses(context);
        case ArtifactType.TaskModel:
            return getTaskModel(context);
        case ArtifactType.UserFlows:
            return getUserFlows(context);
        case ArtifactType.UIScreens:
            return getUIScreens(context);
        default:
            throw new Error('Tipo de artefato desconhecido');
    }
};

import React, { useEffect, useRef, useState } from 'react';
import { GeneratedArtifact } from '../types';

declare global {
    interface Window {
        mermaid?: {
            run: (options: { nodes: Array<Element> }) => void;
        }
    }
}

interface ArtifactDisplayProps {
    artifact: GeneratedArtifact;
}

const ArtifactDisplay: React.FC<ArtifactDisplayProps> = ({ artifact }) => {
    const mermaidRef = useRef<HTMLDivElement>(null);
    const [renderError, setRenderError] = useState<string | null>(null);

    useEffect(() => {
        const renderMermaid = async () => {
             if (window.mermaid && mermaidRef.current) {
                // Find all mermaid divs within this component
                const nodes = Array.from(mermaidRef.current.querySelectorAll('.mermaid')) as Element[];
                if (nodes.length > 0) {
                     // Reset them for re-rendering if needed (remove data-processed attribute)
                     nodes.forEach(node => node.removeAttribute('data-processed'));

                     try {
                        await window.mermaid.run({ nodes: nodes });
                        setRenderError(null);
                     } catch (err: any) {
                         console.error("Mermaid Render Error:", err);
                         setRenderError("Erro de sintaxe no diagrama gerado. Exibindo código fonte.");
                     }
                }
            }
        };

        renderMermaid();
    }, [artifact]);

    // Helper function to download mermaid SVG as PNG
    const downloadMermaidAsPng = (containerId: string, filename: string) => {
        const container = document.getElementById(containerId);
        if (!container) return;

        const svg = container.querySelector('svg');
        if (!svg) {
            alert('Erro: O diagrama ainda não foi renderizado completamente. Tente novamente em alguns instantes.');
            return;
        }

        // 1. Determine Dimensions
        // Try to use viewBox for the most accurate intrinsic size
        const viewBox = svg.getAttribute('viewBox');
        let sourceWidth = svg.getBoundingClientRect().width;
        let sourceHeight = svg.getBoundingClientRect().height;

        if (viewBox) {
            const parts = viewBox.split(/\s+|,/).filter(p => p.trim() !== '');
            if (parts.length === 4) {
                // viewBox = min-x min-y width height
                sourceWidth = parseFloat(parts[2]);
                sourceHeight = parseFloat(parts[3]);
            }
        }

        // If dimensions are still 0 or too small (rare), fallback to a default
        if (sourceWidth < 10) sourceWidth = 800;
        if (sourceHeight < 10) sourceHeight = 600;

        const serializer = new XMLSerializer();
        let source = serializer.serializeToString(svg);

        // Add namespaces
        if (!source.match(/^<svg[^>]+xmlns="http\:\/\/www\.w3\.org\/2000\/svg"/)) {
            source = source.replace(/^<svg/, '<svg xmlns="http://www.w3.org/2000/svg"');
        }
        if (!source.match(/^<svg[^>]+xmlns:xlink/)) {
            source = source.replace(/^<svg/, '<svg xmlns:xlink="http://www.w3.org/1999/xlink"');
        }

        const img = new Image();
        const svgBlob = new Blob([source], { type: 'image/svg+xml;charset=utf-8' });
        const url = URL.createObjectURL(svgBlob);

        img.onload = function () {
            const canvas = document.createElement('canvas');
            // 2. High Resolution Settings
            const scale = 4; // 4x scale for high DPI / crisp text
            const padding = 20; // Padding around the diagram

            canvas.width = (sourceWidth + padding * 2) * scale;
            canvas.height = (sourceHeight + padding * 2) * scale;

            const ctx = canvas.getContext('2d');
            if (ctx) {
                // Background color (Zinc 900 to match theme)
                ctx.fillStyle = "#18181b"; 
                ctx.fillRect(0, 0, canvas.width, canvas.height);

                // Scale coordinate system
                ctx.scale(scale, scale);

                // Draw image with padding
                ctx.drawImage(img, padding, padding, sourceWidth, sourceHeight);

                const imgURI = canvas.toDataURL('image/png');

                const evt = new MouseEvent('click', {
                    view: window,
                    bubbles: false,
                    cancelable: true
                });

                const a = document.createElement('a');
                a.setAttribute('download', `${filename}.png`);
                a.setAttribute('href', imgURI);
                a.setAttribute('target', '_blank');
                a.dispatchEvent(evt);
            }
            URL.revokeObjectURL(url);
        };
        img.src = url;
    };

    // Case 0: Multiple Artifacts (e.g. User Flows per module)
    if (artifact.multiArtifacts && artifact.multiArtifacts.length > 0) {
        return (
            <div ref={mermaidRef} className="space-y-8">
                 <div className="text-xs font-bold text-sky-400 uppercase mb-2 tracking-wider ml-1">
                    Fluxos Gerados ({artifact.multiArtifacts.length})
                </div>
                {renderError && (
                    <div className="bg-red-900/30 border border-red-500/30 p-4 rounded-xl text-red-300 text-sm mb-4">
                        {renderError}
                    </div>
                )}
                {artifact.multiArtifacts.map((sub, index) => {
                    const uniqueId = `mermaid-multi-${index}-${Date.now()}`;
                    return (
                        <div key={index} className="bg-zinc-900/60 backdrop-blur-md p-6 rounded-xl border border-white/10 shadow-inner group overflow-hidden">
                            <div className="flex justify-between items-center mb-4 border-b border-white/5 pb-2">
                                <h4 className="text-sm font-bold text-white">{sub.title}</h4>
                                {sub.type === 'mermaid' && (
                                    <button 
                                        onClick={() => downloadMermaidAsPng(uniqueId, sub.title.replace(/\s+/g, '_'))}
                                        className="text-xs px-3 py-1.5 rounded-lg bg-sky-500/10 text-sky-400 hover:bg-sky-500/20 border border-sky-500/30 transition-colors"
                                    >
                                        Baixar Imagem
                                    </button>
                                )}
                            </div>

                            {sub.type === 'mermaid' ? (
                                <div id={uniqueId} className="overflow-x-auto pb-2">
                                    <pre className="mermaid language-mermaid text-center">
                                        {sub.content}
                                    </pre>
                                </div>
                            ) : (
                                <div className="whitespace-pre-wrap text-sm text-gray-300">{sub.content}</div>
                            )}
                        </div>
                    );
                })}
            </div>
        );
    }

    // Case 1: Single Mermaid Diagram
    if (artifact.isMermaid) {
        const uniqueId = `mermaid-single-${Date.now()}`;
        return (
            <div ref={mermaidRef}>
                <div className="flex justify-between items-end mb-2">
                    <div className="text-xs font-bold text-sky-400 uppercase tracking-wider ml-1">
                        Diagrama Gerado
                    </div>
                    <button 
                        onClick={() => downloadMermaidAsPng(uniqueId, 'diagrama_fluxo')}
                        className="text-xs px-3 py-1.5 rounded-lg bg-sky-500/10 text-sky-400 hover:bg-sky-500/20 border border-sky-500/30 transition-colors"
                    >
                        Baixar Imagem (PNG)
                    </button>
                </div>
                 {renderError && (
                    <div className="bg-red-900/30 border border-red-500/30 p-4 rounded-xl text-red-300 text-sm mb-4">
                        {renderError}
                    </div>
                )}
                <div id={uniqueId} className="bg-zinc-900/60 backdrop-blur-md p-6 rounded-xl border border-white/10 shadow-inner overflow-x-auto pb-4">
                    <pre className="mermaid language-mermaid text-center">
                        {artifact.text}
                    </pre>
                </div>
            </div>
        );
    }

    // Case 2: UI Screens (Keep Visual Image, Truncate Text)
    if (artifact.imageUrl) {
         return (
            <div className="space-y-4">
                 <div className="text-xs font-bold text-violet-400 uppercase mb-2 tracking-wider ml-1">
                    Interface Gerada
                </div>
                <div className={`flex justify-center w-full`}>
                    <div className={`relative rounded-xl overflow-hidden shadow-2xl border-4 border-zinc-800/50 w-full max-w-sm`}>
                        <img
                            src={artifact.imageUrl}
                            alt="Artefato Gerado"
                            className="w-full h-full object-cover"
                        />
                         <div className="absolute inset-0 shadow-[inset_0_0_20px_rgba(0,0,0,0.5)] pointer-events-none"></div>
                    </div>
                </div>
                 <div className="prose prose-invert prose-sm max-w-none bg-zinc-950/40 backdrop-blur-sm p-4 rounded-xl border border-white/5 shadow-inner opacity-80">
                    <p className="text-xs text-gray-400 mb-1 font-bold uppercase">Resumo do Prompt:</p>
                    <div className="whitespace-pre-wrap font-sans text-gray-300 leading-relaxed text-sm line-clamp-3">
                         {artifact.text}
                    </div>
                </div>
            </div>
         )
    }

    // Case 3: Text Artifacts (Personas, Observations, Reports, etc.)

    // Remove markdown image syntax `![alt](url)` to avoid raw base64 mess in summary
    // and replace with a placeholder.
    const textWithoutImages = artifact.text.replace(/!\[(.*?)\]\(.*?\)/g, ' [Imagem disponível no PDF] ');

    const PREVIEW_LIMIT = 300;
    const isLong = textWithoutImages.length > PREVIEW_LIMIT;
    const summaryText = isLong 
        ? textWithoutImages.substring(0, PREVIEW_LIMIT).trim() + "..." 
        : textWithoutImages;

    return (
        <div className="space-y-3">
            <div className="text-xs font-bold text-orange-400 uppercase tracking-wider ml-1">
                Resumo do Resultado
            </div>
            <div className="prose prose-invert prose-sm sm:prose-base max-w-none bg-zinc-950/40 backdrop-blur-sm p-6 rounded-2xl border border-white/5 shadow-inner relative overflow-hidden">
                <div className="whitespace-pre-wrap font-sans text-gray-200 leading-relaxed">
                    {summaryText}
                </div>

                {/* Visual fade effect for truncated text */}
                {isLong && (
                    <div className="absolute bottom-0 left-0 right-0 h-16 bg-gradient-to-t from-zinc-900/90 to-transparent pointer-events-none"></div>
                )}
            </div>

            {isLong && (
                 <div className="flex items-center justify-center gap-2 text-xs text-gray-500 italic mt-1">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                    <span>O artefato completo (com imagens e formatação) está disponível nos botões de download abaixo.</span>
                </div>
            )}
        </div>
    );
};

