const safeParseJson = (jsonString: string): any => {
    // Attempt to find JSON within markdown code fences
    const match = jsonString.match(/```(json)?\s*([\s\S]*?)\s*```/);
    let textToParse = jsonString.trim();

    if (match && match[2]) {
        textToParse = match[2];
    } else {
        // Fallback for cases where there are no code fences, but maybe leading/trailing text
        const firstBrace = textToParse.indexOf('{');
        const lastBrace = textToParse.lastIndexOf('}');
        const firstBracket = textToParse.indexOf('[');
        const lastBracket = textToParse.lastIndexOf(']');

        // Determine if it's an object or array and slice accordingly
        if (firstBracket !== -1 && lastBracket !== -1 && (firstBrace === -1 || firstBracket < firstBrace)) {
             textToParse = textToParse.substring(firstBracket, lastBracket + 1);
        } else if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
            textToParse = textToParse.substring(firstBrace, lastBrace + 1);
        }
    }

    try {
        let parsed = JSON.parse(textToParse);
        // Handle cases where the model returns a stringified JSON object
        if (typeof parsed === 'string') {
            parsed = JSON.parse(parsed);
        }
        return parsed;
    } catch (error) {
        console.error("Failed to parse JSON:", textToParse);
        // Do not throw immediately, let caller handle or return null to trigger fallback
        return null;
    }
};

// Helper function to clean Mermaid code
const cleanMermaidCode = (code: string): string => {
    if (!code) return '';

    // 1. Remove markdown code blocks and HTML
    let clean = code
        .replace(/```mermaid/gi, '')
        .replace(/```/g, '')
        .replace(/<br\s*\/?>/gi, '\\n')
        .replace(/<[^>]*>/g, '');

    clean = clean.trim();

    // 2. Scan for valid keywords to remove conversational prefixes
    const lines = clean.split('\n');
    const keywords = [
        'graph', 'flowchart', 'sequenceDiagram', 'classDiagram', 
        'stateDiagram', 'stateDiagram-v2', 'erDiagram', 'gantt', 
        'pie', 'journey', 'mindmap', 'timeline'
    ];

    let startLineIndex = -1;
    for (let i = 0; i < lines.length; i++) {
      const trimmedLine = lines[i].trim();
      if (keywords.some(kw => trimmedLine.startsWith(kw))) {
        startLineIndex = i;
        break;
      }
    }
    if (startLineIndex !== -1) {
      clean = lines.slice(startLineIndex).join('\n');
    } else {
        // If no header found, assume graph TD if it looks like a graph
        if (clean.includes('-->') || clean.includes('---')) {
            clean = 'graph TD\n' + clean;
        }
    }

    // 3. AGGRESSIVE QUOTE SANITIZATION
    // The most common error is nested double quotes or unescaped strings inside brackets.
    // Strategy: 
    // a. Replace ALL double quotes with single quotes globally.
    // b. Find bracket contents and wrap them in fresh double quotes.

    // Replace all double quotes with single quotes to prevent breaking the structure later
    clean = clean.replace(/"/g, "'");

    // Helper to wrap content in double quotes
    const wrap = (content: string) => `"${content.trim()}"`;

    // Regex Explanation:
    // \[([^\]]+)\] : Match '[' followed by anything that IS NOT ']' until ']'
    // This assumes no nested brackets [ [ ] ], which usually don't happen in simple flowchart labels.

    // Clean Square Brackets: [Content] -> ["Content"]
    clean = clean.replace(/\[([^\]]+)\]/g, (match, content) => `[${wrap(content)}]`);

    // Clean Round Brackets: (Content) -> ("Content")
    // NOTE: We rely on the prompt to avoid nested parentheses. If they exist, this regex might cut short.
    clean = clean.replace(/\(([^)]+)\)/g, (match, content) => `(${wrap(content)})`);

    // Clean Rhombus: {Content} -> {"Content"}
    clean = clean.replace(/\{([^}]+)\}/g, (match, content) => `{${wrap(content)}}`);

    return clean.trim();
};

