const getUserJourney = async (context: string): Promise<GeneratedArtifact> => {
    // 1. Identify ALL Personas from the context
    // Priority: Try to use Gemini to extract JSON
    const identificationPrompt = `
    Analise o texto completo abaixo buscando identificar TODAS as Personas definidas.

    Geralmente elas aparecem como Títulos (H1 ou H2) seguidos de descrições ou blocos com "# Nome".
    Procure por: "# Nome: Papel", "# Nome - Papel", "# Nome" ou listas de personas geradas anteriormente.

    Seu objetivo é listar TODOS os perfis encontrados, não apenas um.

    Retorne EXCLUSIVAMENTE um JSON com a lista de todas as personas encontradas:
    [
        { "name": "Nome identificado", "role": "Papel ou Profissão identificada" }
    ]

    Contexto:
    ${context}
    `;

    let targets: { name: string; role: string }[] = [];
    try {
        const idResponse = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: identificationPrompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: { name: { type: Type.STRING }, role: { type: Type.STRING } }
                    }
                }
            }
        });
        const parsed = safeParseJson(idResponse.text);
        if (parsed) targets = parsed;
    } catch (e) {
        console.warn("Failed to parse personas for journey via JSON, attempting fallback.");
    }

    // 2. Fallback: Regex extraction if JSON failed or returned nothing
    // This looks for lines starting with '#' that are NOT known artifact headers.
    if (targets.length === 0) {
        const headerRegex = /^#\s+(.+)$/gm;
        let match;

        const knownArtifactHeaders = [
            "Resumir Observação", "Gerar Perguntas", "Resumir Entrevista", 
            "Modelo Organizacional", "Criar Personas", "Gerar Modelo", 
            "Gerar Mapa", "Jornada do Usuário", "Geração de Hipóteses", 
            "Desenhar Fluxos", "Geração de Telas", "Mapas de Empatia", 
            "Tabela MO1", "Tabela MO5", "Observação", "Entrevista", "Relatório"
        ];

        while ((match = headerRegex.exec(context)) !== null) {
            const headerText = match[1].trim();
            // Check if it's a known artifact header (approximate match)
            const isKnown = knownArtifactHeaders.some(k => headerText.includes(k));

            // Personas usually have short headers (< 60 chars) and aren't system headers
            if (!isKnown && headerText.length < 60) { 
                // Try to split Name: Role if present
                const parts = headerText.split(/[:|-]/);
                const name = parts[0].trim();
                const role = parts.length > 1 ? parts[1].trim() : "Usuário Identificado";

                // Avoid duplicates
                if (!targets.some(t => t.name === name)) {
                    targets.push({ name, role });
                }
            }
        }
    }

    // 3. Final Fallback if truly nothing found
    if (targets.length === 0) {
        targets.push({ name: "Usuário Padrão", role: "Principal" });
    }

    let fullMarkdown = "";

    // 4. Generate Journey for each identified persona
    for (const target of targets) {
        const prompt = `Atue como um UX Designer Especialista.
        Crie uma Jornada do Usuário (User Journey Map) baseada no framework de Gibbons (2018) EXCLUSIVAMENTE para a persona: **${target.name}** (${target.role}).

        INSTRUÇÃO DE ESCRITA:
        Escreva uma jornada que represente o dia a dia desse perfil específico.
        **IMPORTANTE**: A narrativa deve ser IMPESSOAL e GENÉRICA. 
        - NÃO use o nome "${target.name}" no texto das etapas.
        - Use termos como "O usuário", "O ${target.role}", "O cliente".
        - O objetivo é que a jornada sirva para qualquer pessoa que se encaixe nesse arquétipo.
        - NÃO USE TAGS HTML (sem <br>, <b>, etc). Use apenas Markdown.
        - NÃO INCLUA textos de introdução ou conclusão (Ex: "Com certeza", "Aqui está a jornada", "Espero que ajude"). Comece direto pelo Cenário.

        FORMATO OBRIGATÓRIO (MARKDOWN PURO):

        ### 1. Cenário
        (Descreva o contexto e o objetivo para este perfil específico)

        ### 2. Ações
        (Lista numerada das ações. Ex: 1. O usuário abre o app...)

        ### 3. Oportunidades
        (Lista de melhorias possíveis)

        ### 4. Serviços Externos
        (Ferramentas ou pessoas envolvidas)

        Contexto do Projeto:
        ${context}
        `;

        try {
            const response = await ai.models.generateContent({
                model: "gemini-2.5-pro",
                contents: prompt
            });

            // Clean any potential HTML
            const cleanText = response.text.replace(/<[^>]*>?/gm, '');

            // Prioritize Role/Archetype for the header to keep it impersonal.
            // Fallback to name only if role is missing or generic placeholder.
            let journeyTitle = target.role;
            if (!journeyTitle || journeyTitle.length < 3 || journeyTitle === 'Principal' || journeyTitle === 'Usuário Identificado' || journeyTitle === 'Usuário Padrão') {
                journeyTitle = target.name;
            }

            fullMarkdown += `## Jornada: ${journeyTitle}\n\n${cleanText}\n\n---\n\n`;
        } catch (err) {
            console.error(`Error generating journey for ${target.name}`, err);
            fullMarkdown += `## Jornada: ${target.name}\n\n*Erro ao gerar jornada para esta persona.*\n\n---\n\n`;
        }
    }

    return { text: fullMarkdown };
};

