const getUserFlows = async (context: string): Promise<GeneratedArtifact> => {
    // Attempt 1: Strict JSON for multiple modules (Preferred)
    const prompt = `Atue como um Arquiteto de Informação Sênior. 

    TAREFA: Analise EXAUSTIVAMENTE o contexto, procurando especificamente pela seção de "Geração de Hipóteses" ou "Árvore de Funcionalidades" onde os módulos foram definidos.

    OBJETIVO:
    1. Identifique TODOS os Módulos listados na etapa anterior (geralmente marcados como "### Módulo: [Nome]").
    2. Para CADA Módulo encontrado, gere um diagrama de atividades (User Flow) independente usando Mermaid.js.
    3. NÃO agrupe tudo em um único gráfico. Crie um objeto separado no array JSON para cada módulo.

    INSTRUÇÃO CRÍTICA DE SINTAXE MERMAID:
    1. O código DEVE começar com "graph TD".
    2. OBRIGATÓRIO: Texto dos nós entre aspas duplas: A["Texto"] --> B["Texto"].
    3. SEM parênteses curvos () dentro do texto.
    4. Texto curto e conciso.

    OUTPUT ESPERADO (JSON ARRAY):
    Retorne APENAS um Array JSON.
    [
        {
            "title": "Fluxo: [Nome do Módulo 1]",
            "code": "graph TD\\n..."
        },
        {
            "title": "Fluxo: [Nome do Módulo 2]",
            "code": "graph TD\\n..."
        }
    ]

    Contexto Completo:
    ${context}`;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-pro",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            title: { type: Type.STRING },
                            code: { type: Type.STRING }
                        }
                    }
                }
            }
        });

        const parsed = safeParseJson(response.text);

        if (Array.isArray(parsed) && parsed.length > 0) {
            // Map the parsed JSON to the SubArtifact structure
            const artifacts = parsed.map((item: any) => {
                const cleanCode = cleanMermaidCode(item.code || "");
                return {
                    title: item.title,
                    content: cleanCode,
                    type: 'mermaid' as const
                };
            }).filter(a => a.content.length > 10); // Check length to be sure it has some content

            if (artifacts.length > 0) {
                 return { 
                    text: "Fluxos de Usuário gerados para cada módulo identificado.", 
                    multiArtifacts: artifacts 
                };
            }
        }
    } catch (error) {
        console.warn("Primary multi-flow generation failed, attempting simple fallback...", error);
    }

    // Attempt 2: Fallback to Single Comprehensive Diagram (Simple & Reliable)
    const fallbackPrompt = `Atue como um Arquiteto de Informação.

    Analise o contexto e crie UM ÚNICO diagrama de fluxo de usuário (User Flow) cobrindo os principais módulos e funcionalidades identificados.

    Use sintaxe Mermaid.js.
    Comece com "graph TD".
    Use aspas nos textos dos nós.

    Contexto: ${context}`;

    try {
        const fallbackResponse = await ai.models.generateContent({
            model: "gemini-2.5-flash", // Use flash for speed/robustness
            contents: fallbackPrompt
        });

        const code = cleanMermaidCode(fallbackResponse.text);
        if (code.length < 10) throw new Error("Fallback generated empty code");

        return { 
            text: code, 
            isMermaid: true 
        };
    } catch (e) {
        console.error("Fallback failed:", e);
        throw new Error("Não foi possível gerar os fluxos. O contexto pode estar muito complexo ou o serviço indisponível.");
    }
};

const getUIScreens = async (context: string): Promise<GeneratedArtifact> => {
    const uiPrompt = `Atue como um Diretor de Arte de UI Design. Sua tarefa é escrever um prompt de geração de imagem textual altamente detalhado para criar uma tela de interface de alta fidelidade.

Considere as personas, o fluxo e os requisitos.
A resposta DEVE ser um objeto JSON com o campo "imagePrompt".

O "imagePrompt" deve descrever a tela visualmente para um modelo de IA generativa (como Imagen ou Midjourney):
- Descreva o tipo de tela (ex: Dashboard, Login, Feed, Detalhe de Produto).
- Defina o estilo visual (ex: Neomorfismo, Material Design, Minimalista, Dark Mode, Cores vibrantes).
- Descreva elementos específicos: Tipografia (Sans-serif, bold headers), Botões (arredondados, gradiente), Ícones (outline, filled).
- Descreva o conteúdo fictício visível para tornar a tela realista.

Contexto do Projeto: ${context}`;

    let uiData;
    const maxRetries = 2;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
        try {
            const uiResponse = await ai.models.generateContent({
                model: "gemini-2.5-pro",
                contents: uiPrompt,
                config: {
                  responseMimeType: "application/json",
                  responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                      imagePrompt: { type: Type.STRING },
                    }
                  }
                }
            });

            const parsedData = safeParseJson(uiResponse.text);

            if (parsedData && typeof parsedData.imagePrompt === 'string' && parsedData.imagePrompt.trim()) {
                uiData = parsedData;
                break; // Success
            } else {
                console.warn(`Attempt ${attempt} failed: Invalid UI screen data.`, parsedData);
            }
        } catch (error) {
            console.error(`Attempt ${attempt} failed with error:`, error);
        }

        if (attempt < maxRetries) {
            console.log(`Retrying UI screen generation... (${attempt}/${maxRetries})`);
        }
    }

    if (!uiData) {
        console.error("Failed to generate valid UI screen data after all retries.");
        throw new Error("A resposta do modelo para a tela de UI veio incompleta, mesmo após tentar novamente.");
    }

    const finalImagePrompt = `Mobile app UI screen design, high fidelity, HQ, 4k. ${uiData.imagePrompt}`;

    const imageResponse = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: finalImagePrompt,
        config: {
          numberOfImages: 1,
          aspectRatio: "9:16",
        }
    });

    const base64Image = imageResponse.generatedImages[0].image.imageBytes;
    const imageUrl = `data:image/png;base64,${base64Image}`;

    return { text: "Aqui está uma proposta de UI para a tela solicitada, baseada em todo o contexto do projeto.", imageUrl };
};

export const generateArtifact = async (artifactType: ArtifactType, context: string): Promise<GeneratedArtifact> => {
    switch (artifactType) {
        case ArtifactType.Observation:
            return getObservationSummary(context);
        case ArtifactType.InterviewQuestions:
            return getInterviewQuestions(context);
        case ArtifactType.SummarizeInterview:
            return getInterviewSummary(context);
        case ArtifactType.MOTables:
            return getMOTables(context);
        case ArtifactType.Personas:
            return getPersona(context);
        case ArtifactType.AgentModel:
            return getAgentModel(context);
        case ArtifactType.EmpathyMap:
            return getEmpathyMap(context);
        case ArtifactType.UserJourney:
            return getUserJourney(context);
        case ArtifactType.HypothesisGeneration:
            return getHypotheses(context);
        case ArtifactType.TaskModel:
            return getTaskModel(context);
        case ArtifactType.UserFlows:
            return getUserFlows(context);
        case ArtifactType.UIScreens:
            return getUIScreens(context);
        default:
            throw new Error('Tipo de artefato desconhecido');
    }
};

import React, { useEffect, useRef, useState } from 'react';
import { GeneratedArtifact } from '../types';
import { DocumentTextIcon } from './Icons';

declare global {
    interface Window {
        mermaid?: {
            run: (options: { nodes: Array<Element> }) => void;
        }
    }
}

interface ArtifactDisplayProps {
    artifact: GeneratedArtifact;
}

const ArtifactDisplay: React.FC<ArtifactDisplayProps> = ({ artifact }) => {
    const mermaidRef = useRef<HTMLDivElement>(null);
    const [renderError, setRenderError] = useState<string | null>(null);

    useEffect(() => {
        const renderMermaid = async () => {
             if (window.mermaid && mermaidRef.current) {
                // Find all mermaid divs within this component
                const nodes = Array.from(mermaidRef.current.querySelectorAll('.mermaid')) as Element[];
                if (nodes.length > 0) {
                     // Reset them for re-rendering if needed (remove data-processed attribute)
                     nodes.forEach(node => node.removeAttribute('data-processed'));

                     try {
                        await window.mermaid.run({ nodes: nodes });
                        setRenderError(null);
                     } catch (err: any) {
                         console.error("Mermaid Render Error:", err);
                         setRenderError("Erro de sintaxe no diagrama gerado. Exibindo código fonte.");
                     }
                }
            }
        };

        // Small timeout to ensure DOM is ready for Mermaid
        const timeoutId = setTimeout(() => {
            renderMermaid();
        }, 100);

        return () => clearTimeout(timeoutId);
    }, [artifact]);

    // Helper function to download mermaid SVG as PNG
    const downloadMermaidAsPng = (containerId: string, filename: string) => {
        const container = document.getElementById(containerId);
        if (!container) return;

        const svg = container.querySelector('svg');
        if (!svg) {
            alert('Erro: O diagrama ainda não foi renderizado completamente. Tente novamente em alguns instantes.');
            return;
        }

        // 1. Determine Dimensions
        const viewBox = svg.getAttribute('viewBox');
        let sourceWidth = svg.getBoundingClientRect().width;
        let sourceHeight = svg.getBoundingClientRect().height;

        if (viewBox) {
            const parts = viewBox.split(/\s+|,/).filter(p => p.trim() !== '');
            if (parts.length === 4) {
                sourceWidth = parseFloat(parts[2]);
                sourceHeight = parseFloat(parts[3]);
            }
        }

        if (sourceWidth < 10) sourceWidth = 800;
        if (sourceHeight < 10) sourceHeight = 600;

        const serializer = new XMLSerializer();
        let source = serializer.serializeToString(svg);

        // Add namespaces if missing
        if (!source.match(/^<svg[^>]+xmlns="http\:\/\/www\.w3\.org\/2000\/svg"/)) {
            source = source.replace(/^<svg/, '<svg xmlns="http://www.w3.org/2000/svg"');
        }

        const img = new Image();
        const svgBlob = new Blob([source], { type: 'image/svg+xml;charset=utf-8' });
        const url = URL.createObjectURL(svgBlob);

        img.onload = function () {
            const canvas = document.createElement('canvas');
            const scale = 4; // High res
            const padding = 40;

            canvas.width = (sourceWidth + padding * 2) * scale;
            canvas.height = (sourceHeight + padding * 2) * scale;

            const ctx = canvas.getContext('2d');
            if (ctx) {
                ctx.fillStyle = "#18181b"; // Dark background
                ctx.fillRect(0, 0, canvas.width, canvas.height);

                ctx.scale(scale, scale);
                ctx.drawImage(img, padding, padding, sourceWidth, sourceHeight);

                const imgURI = canvas.toDataURL('image/png');

                const evt = new MouseEvent('click', {
                    view: window,
                    bubbles: false,
                    cancelable: true
                });

                const a = document.createElement('a');
                a.setAttribute('download', `${filename}.png`);
                a.setAttribute('href', imgURI);
                a.setAttribute('target', '_blank');
                a.dispatchEvent(evt);
            }
            URL.revokeObjectURL(url);
        };
        img.src = url;
    };

    // Case 0: Multiple Artifacts (User Flows per module)
    if (artifact.multiArtifacts && artifact.multiArtifacts.length > 0) {
        return (
            <div ref={mermaidRef} className="space-y-12">
                 <div className="flex items-center gap-2 mb-6 border-b border-white/10 pb-4">
                    <span className="p-2 bg-sky-500/20 rounded-lg text-sky-300">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 5a1 1 0 011-1h14a1 1 0 011 1v2a1 1 0 01-1 1H5a1 1 0 01-1-1V5zM4 13a1 1 0 011-1h6a1 1 0 011 1v6a1 1 0 01-1 1H5a1 1 0 01-1-1v-6zM16 13a1 1 0 011-1h2a1 1 0 011 1v6a1 1 0 01-1 1h-2a1 1 0 01-1-1v-6z" />
                        </svg>
                    </span>
                    <h3 className="text-lg font-bold text-gray-100">
                        Fluxos de Usuário por Módulo ({artifact.multiArtifacts.length})
                    </h3>
                </div>

                {renderError && (
                    <div className="bg-red-900/30 border border-red-500/30 p-4 rounded-xl text-red-300 text-sm mb-4">
                        {renderError}
                    </div>
                )}

                {artifact.multiArtifacts.map((sub, index) => {
                    const uniqueId = `mermaid-multi-${index}-${Date.now()}`;
                    return (
                        <div key={index} className="flex flex-col bg-zinc-900/40 border border-white/5 rounded-2xl overflow-hidden shadow-lg">
                            {/* 1. TITLE */}
                            <div className="bg-zinc-800/60 px-6 py-4 border-b border-white/5">
                                <h4 className="text-md font-bold text-sky-400 flex items-center gap-3">
                                    <span className="flex-shrink-0 w-8 h-8 rounded-full bg-sky-500/20 flex items-center justify-center text-sm border border-sky-500/30 font-mono">
                                        {index + 1}
                                    </span>
                                    <span className="text-gray-100">{sub.title}</span>
                                </h4>
                            </div>

                            {/* 2. DIAGRAM */}
                            <div className="p-6 bg-[#0f0f11] flex justify-center w-full">
                                {sub.type === 'mermaid' ? (
                                    <div id={uniqueId} className="w-full flex justify-center [&_svg]:max-w-full [&_svg]:h-auto [&_svg]:mx-auto">
                                        <pre className="mermaid language-mermaid bg-transparent text-center w-full">
                                            {sub.content}
                                        </pre>
                                    </div>
                                ) : (
                                    <div className="whitespace-pre-wrap text-sm text-gray-300">{sub.content}</div>
                                )}
                            </div>

                            {/* 3. DOWNLOAD BUTTON (Bottom) */}
                            {sub.type === 'mermaid' && (
                                <div className="px-6 py-4 bg-zinc-800/40 border-t border-white/5 flex justify-end">
                                    <button 
                                        onClick={() => downloadMermaidAsPng(uniqueId, sub.title.replace(/\s+/g, '_'))}
                                        className="flex items-center gap-2 px-4 py-2 rounded-lg bg-sky-600/20 text-sky-300 hover:bg-sky-600/30 border border-sky-500/30 transition-all duration-300 text-sm font-medium shadow-lg shadow-sky-900/10 hover:shadow-sky-900/30"
                                    >
                                        <DocumentTextIcon />
                                        Baixar Imagem deste Fluxo
                                    </button>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        );
    }

    // Case 1: Single Mermaid Diagram
    if (artifact.isMermaid) {
        const uniqueId = `mermaid-single-${Date.now()}`;
        return (
            <div ref={mermaidRef}>
                <div className="flex justify-between items-end mb-2">
                    <div className="text-xs font-bold text-sky-400 uppercase tracking-wider ml-1">
                        Diagrama Gerado
                    </div>
                </div>
                 {renderError && (
                    <div className="bg-red-900/30 border border-red-500/30 p-4 rounded-xl text-red-300 text-sm mb-4">
                        {renderError}
                    </div>
                )}
                <div id={uniqueId} className="bg-zinc-900/60 backdrop-blur-md p-6 rounded-xl border border-white/10 shadow-inner w-full flex justify-center mb-3 [&_svg]:max-w-full [&_svg]:h-auto [&_svg]:mx-auto">
                    <pre className="mermaid language-mermaid text-center w-full">
                        {artifact.text}
                    </pre>
                </div>

                <button 
                    onClick={() => downloadMermaidAsPng(uniqueId, 'diagrama_fluxo')}
                    className="w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl bg-sky-600/20 text-sky-300 hover:bg-sky-600/30 border border-sky-500/30 transition-all"
                >
                    <DocumentTextIcon />
                    Baixar Imagem (PNG)
                </button>
            </div>
        );
    }

    // Case 2: UI Screens (Keep Visual Image, Truncate Text)
    if (artifact.imageUrl) {
         return (
            <div className="space-y-4">
                 <div className="text-xs font-bold text-violet-400 uppercase mb-2 tracking-wider ml-1">
                    Interface Gerada
                </div>
                <div className={`flex justify-center w-full`}>
                    <div className={`relative rounded-xl overflow-hidden shadow-2xl border-4 border-zinc-800/50 w-full max-w-sm`}>
                        <img
                            src={artifact.imageUrl}
                            alt="Artefato Gerado"
                            className="w-full h-full object-cover"
                        />
                         <div className="absolute inset-0 shadow-[inset_0_0_20px_rgba(0,0,0,0.5)] pointer-events-none"></div>
                    </div>
                </div>
                 <div className="prose prose-invert prose-sm max-w-none bg-zinc-950/40 backdrop-blur-sm p-4 rounded-xl border border-white/5 shadow-inner opacity-80">
                    <p className="text-xs text-gray-400 mb-1 font-bold uppercase">Resumo do Prompt:</p>
                    <div className="whitespace-pre-wrap font-sans text-gray-300 leading-relaxed text-sm line-clamp-3">
                         {artifact.text}
                    </div>
                </div>
            </div>
         )
    }

    // Case 3: Text Artifacts (Personas, Observations, Reports, etc.)
    const textWithoutImages = artifact.text.replace(/!\[(.*?)\]\(.*?\)/g, ' [Imagem disponível no PDF] ');

    const PREVIEW_LIMIT = 500;
    const isLong = textWithoutImages.length > PREVIEW_LIMIT;
    const summaryText = isLong 
        ? textWithoutImages.substring(0, PREVIEW_LIMIT).trim() + "..." 
        : textWithoutImages;

    return (
        <div className="space-y-3">
            <div className="text-xs font-bold text-orange-400 uppercase tracking-wider ml-1">
                Resumo do Resultado
            </div>
            <div className="prose prose-invert prose-sm sm:prose-base max-w-none bg-zinc-950/40 backdrop-blur-sm p-6 rounded-2xl border border-white/5 shadow-inner relative overflow-hidden">
                <div className="whitespace-pre-wrap font-sans text-gray-200 leading-relaxed">
                    {summaryText}
                </div>

                {isLong && (
                    <div className="absolute bottom-0 left-0 right-0 h-16 bg-gradient-to-t from-zinc-900/90 to-transparent pointer-events-none"></div>
                )}
            </div>

            {isLong && (
                 <div className="flex items-center justify-center gap-2 text-xs text-gray-500 italic mt-1">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
