const getUserFlows = async (context: string): Promise<GeneratedArtifact> => {
    // Attempt 1: Strict JSON for multiple modules (Preferred)
    const prompt = `Atue como um Arquiteto de Informação Sênior. 

    TAREFA: Analise EXAUSTIVAMENTE o contexto, procurando especificamente pela seção de "Geração de Hipóteses" ou "Árvore de Funcionalidades" onde os módulos foram definidos.

    OBJETIVO:
    1. Identifique TODOS os Módulos listados na etapa anterior (geralmente marcados como "### Módulo: [Nome]").
    2. Para CADA Módulo encontrado, gere um diagrama de atividades (User Flow) independente usando Mermaid.js.
    3. NÃO agrupe tudo em um único gráfico. Crie um objeto separado no array JSON para cada módulo.

    INSTRUÇÃO CRÍTICA DE SINTAXE MERMAID:
    1. O código DEVE começar com "graph TD".
    2. OBRIGATÓRIO: Use colchetes quadrados [] para todos os nós. Ex: A["Login"] --> B["Home"].
    3. PROIBIDO: NÃO use parênteses curvos () para nós (Ex: NÃO faça A("Texto")). Isso causa erro de parser.
    4. PROIBIDO: NÃO use parênteses dentro do texto do nó.
    5. Texto dos nós SEMPRE entre aspas duplas.

    OUTPUT ESPERADO (JSON ARRAY):
    Retorne APENAS um Array JSON.
    [
        {
            "title": "Fluxo: [Nome do Módulo 1]",
            "code": "graph TD\\nA[\\"Inicio\\"] --> B[\\"Fim\\"]"
        },
        {
            "title": "Fluxo: [Nome do Módulo 2]",
            "code": "graph TD\\n..."
        }
    ]

    Contexto Completo:
    ${context}`;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-pro",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            title: { type: Type.STRING },
                            code: { type: Type.STRING }
                        }
                    }
                }
            }
        });

        const parsed = safeParseJson(response.text);

        if (Array.isArray(parsed) && parsed.length > 0) {
            // Map the parsed JSON to the SubArtifact structure
            const artifacts = parsed.map((item: any) => {
                const cleanCode = cleanMermaidCode(item.code || "");
                return {
                    title: item.title,
                    content: cleanCode,
                    type: 'mermaid' as const
                };
            }).filter(a => a.content.length > 10); // Check length to be sure it has some content

            if (artifacts.length > 0) {
                 return { 
                    text: "Fluxos de Usuário gerados para cada módulo identificado.", 
                    multiArtifacts: artifacts 
                };
            }
        }
    } catch (error) {
        console.warn("Primary multi-flow generation failed, attempting simple fallback...", error);
    }

    // Attempt 2: Fallback to Single Comprehensive Diagram (Simple & Reliable)
    const fallbackPrompt = `Atue como um Arquiteto de Informação.

    Analise o contexto e crie UM ÚNICO diagrama de fluxo de usuário (User Flow) cobrindo os principais módulos e funcionalidades identificados.

    Use sintaxe Mermaid.js.
    Comece com "graph TD".

    REGRAS DE SINTAXE:
    1. Use APENAS colchetes quadrados [] para nós: id["Texto"].
    2. NÃO use parênteses () para nós.
    3. NÃO use parênteses dentro do texto dos nós.

    Contexto: ${context}`;

    try {
        const fallbackResponse = await ai.models.generateContent({
            model: "gemini-2.5-flash", // Use flash for speed/robustness
            contents: fallbackPrompt
        });

        const code = cleanMermaidCode(fallbackResponse.text);
        if (code.length < 10) throw new Error("Fallback generated empty code");

        return { 
            text: code, 
            isMermaid: true 
        };
    } catch (e) {
        console.error("Fallback failed:", e);
        throw new Error("Não foi possível gerar os fluxos. O contexto pode estar muito complexo ou o serviço indisponível.");
    }
};

const getUIScreens = async (context: string): Promise<GeneratedArtifact> => {
    const uiPrompt = `Atue como um Diretor de Arte de UI Design. Sua tarefa é escrever um prompt de geração de imagem textual altamente detalhado para criar uma tela de interface de alta fidelidade.

Considere as personas, o fluxo e os requisitos.
A resposta DEVE ser um objeto JSON com o campo "imagePrompt".

O "imagePrompt" deve descrever a tela visualmente para um modelo de IA generativa (como Imagen ou Midjourney):
- Descreva o tipo de tela (ex: Dashboard, Login, Feed, Detalhe de Produto).
- Defina o estilo visual (ex: Neomorfismo, Material Design, Minimalista, Dark Mode, Cores vibrantes).
- Descreva elementos específicos: Tipografia (Sans-serif, bold headers), Botões (arredondados, gradiente), Ícones (outline, filled).
- Descreva o conteúdo fictício visível para tornar a tela realista.

Contexto do Projeto: ${context}`;

    let uiData;
    const maxRetries = 2;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
        try {
            const uiResponse = await ai.models.generateContent({
                model: "gemini-2.5-pro",
                contents: uiPrompt,
                config: {
                  responseMimeType: "application/json",
                  responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                      imagePrompt: { type: Type.STRING },
                    }
                  }
                }
            });

            const parsedData = safeParseJson(uiResponse.text);

            if (parsedData && typeof parsedData.imagePrompt === 'string' && parsedData.imagePrompt.trim()) {
                uiData = parsedData;
                break; // Success
            } else {
                console.warn(`Attempt ${attempt} failed: Invalid UI screen data.`, parsedData);
            }
        } catch (error) {
            console.error(`Attempt ${attempt} failed with error:`, error);
        }

        if (attempt < maxRetries) {
            console.log(`Retrying UI screen generation... (${attempt}/${maxRetries})`);
        }
    }

    if (!uiData) {
        console.error("Failed to generate valid UI screen data after all retries.");
        throw new Error("A resposta do modelo para a tela de UI veio incompleta, mesmo após tentar novamente.");
    }

    const finalImagePrompt = `Mobile app UI screen design, high fidelity, HQ, 4k. ${uiData.imagePrompt}`;

    const imageResponse = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: finalImagePrompt,
        config: {
          numberOfImages: 1,
          aspectRatio: "9:16",
        }
    });

    const base64Image = imageResponse.generatedImages[0].image.imageBytes;
    const imageUrl = `data:image/png;base64,${base64Image}`;

    return { text: "Aqui está uma proposta de UI para a tela solicitada, baseada em todo o contexto do projeto.", imageUrl };
};

export const generateArtifact = async (artifactType: ArtifactType, context: string): Promise<GeneratedArtifact> => {
    switch (artifactType) {
        case ArtifactType.Observation:
            return getObservationSummary(context);
        case ArtifactType.InterviewQuestions:
            return getInterviewQuestions(context);
        case ArtifactType.SummarizeInterview:
            return getInterviewSummary(context);
        case ArtifactType.MOTables:
            return getMOTables(context);
        case ArtifactType.Personas:
            return getPersona(context);
        case ArtifactType.AgentModel:
            return getAgentModel(context);
        case ArtifactType.EmpathyMap:
            return getEmpathyMap(context);
        case ArtifactType.UserJourney:
            return getUserJourney(context);
        case ArtifactType.HypothesisGeneration:
            return getHypotheses(context);
        case ArtifactType.TaskModel:
            return getTaskModel(context);
        case ArtifactType.UserFlows:
            return getUserFlows(context);
        case ArtifactType.UIScreens:
            return getUIScreens(context);
        default:
            throw new Error('Tipo de artefato desconhecido');
    }
};

