    title: string;
    content: string; // The content (e.g., mermaid code)
    type: 'mermaid' | 'text' | 'image';
}

export interface GeneratedArtifact {
    text: string;
    imageUrl?: string;
    isMermaid?: boolean;
    multiArtifacts?: SubArtifact[];
}

