                        {category.name}
                    </h3>
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                        {category.options.map(option => {
                            const { disabled } = getDependencyStatus(option.type);

                            return (
