const getUserFlows = async (context: string): Promise<GeneratedArtifact> => {
    const prompt = `Identifique os módulos e gere diagramas Mermaid (graph TD) em um array JSON.
    Contexto: ${context}`;
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-pro",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            title: { type: Type.STRING },
                            code: { type: Type.STRING }
                        }
                    }
                }
            }
        });
        const parsed = safeParseJson(response.text);
        if (Array.isArray(parsed)) {
            const artifacts = parsed.map((item: any) => ({
                title: item.title,
                content: cleanMermaidCode(item.code || ""),
                type: 'mermaid' as const
            }));
            return { text: "Fluxos gerados.", multiArtifacts: artifacts };
        }
    } catch (e) {}
    return { text: "Erro ao gerar fluxos.", multiArtifacts: [] };
};

