import React from 'react';
import { ArtifactType } from '../types';
import {
    EyeIcon, MicIcon, UserCircleIcon, BrainCircuitIcon,
    DocumentTextIcon, ClipboardListIcon, ArrowsRightLeftIcon, ComputerDesktopIcon,
    HeartIcon, PuzzlePieceIcon, LightBulbIcon, SwatchIcon, UsersIcon, LockClosedIcon, MapIcon, BeakerIcon, ListCheckIcon, DocumentCheckIcon, MiniBrainIcon, ArchiveIcon, BookOpenIcon, BrainIcon, QuestionMarkIcon, TreeIcon
} from './Icons';

interface OptionSelectorProps {
    onSelect: (type: ArtifactType) => void;
    completedArtifacts: ArtifactType[];
}

const categories = [
    {
        name: 'Empatia',
        icon: <HeartIcon />,
        theme: {
            text: 'text-rose-300',
            bgIcon: 'bg-rose-500/20',
