                >
                    <DocumentTextIcon />
                    Baixar Imagem (PNG)
                </button>
            </div>
        );
    }

    // Case 2: UI Screens
    if (artifact.imageUrl) {
         return (
            <div className="space-y-4">
                 <div className="text-xs font-bold text-violet-400 uppercase mb-2 tracking-wider ml-1">
                    Interface Gerada
                </div>
                <div className={`flex justify-center w-full`}>
                    <div className={`relative rounded-xl overflow-hidden shadow-2xl border-4 border-zinc-800/50 w-full max-w-sm`}>
                        <img
                            src={artifact.imageUrl}
                            alt="Artefato Gerado"
                            className="w-full h-full object-cover"
