import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, ImageRun } from "docx";
import { jsPDF } from "jspdf";

// App Theme Colors for PDF
const THEME = {
    bg: [9, 9, 11],         // Zinc 950
    cardBg: [24, 24, 27],   // Zinc 900
    text: [228, 228, 231],  // Zinc 200 (Brighter for better contrast)
    textBold: [255, 255, 255], // White
    accent: [249, 115, 22], // Orange 500
    accentSecondary: [251, 191, 36], // Amber 400
    border: [63, 63, 70]    // Zinc 700
};

/**
 * Limpa o texto removendo tags HTML e emojis para garantir compatibilidade
 * e atender aos requisitos de exportação limpa.
 */
const cleanTextForExport = (text: string): string => {
    if (!text) return "";

    // 1. Remover tags HTML (ex: <br>, <div>, etc)
    let cleaned = text.replace(/<[^>]*>/g, '');

    // 2. Remover Emojis usando regex de ranges Unicode
    // Abrange a maioria dos símbolos pictográficos e variações
    cleaned = cleaned.replace(/([\u2700-\u27BF]|[\uE000-\uF8FF]|\uD83C[\uDC00-\uDFFF]|\uD83D[\uDC00-\uDFFF]|[\u2011-\u26FF]|\uD83E[\uDD10-\uDDFF])/g, '');

    return cleaned;
};

export const generateAndDownloadDocx = async (title: string, subtitle: string, content: string) => {
    // Pré-processamento: Identificar imagens antes de limpar o texto para não quebrar os URIs de dados
    const lines = content.split('\n');
    const docChildren: (Paragraph)[] = [];

    // Title
    docChildren.push(
        new Paragraph({
            text: cleanTextForExport(title),
            heading: HeadingLevel.TITLE,
            alignment: AlignmentType.CENTER,
            spacing: { after: 300 },
        })
    );

    // Subtitle
    docChildren.push(
        new Paragraph({
            text: cleanTextForExport(subtitle),
            heading: HeadingLevel.HEADING_2,
            alignment: AlignmentType.CENTER,
            spacing: { after: 300 },
        })
    );

    // Process Content
    // Captures: 1=AltText, 2=FullDataURI, 3=MimeSubtype (e.g., png, jpeg)
    const imageRegex = /!\[(.*?)\]\((data:image\/(.*?);base64,.*?)\)/;

    for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) {
            docChildren.push(new Paragraph({ text: "" }));
            continue;
        }

        const imageMatch = trimmed.match(imageRegex);

        if (imageMatch) {
            try {
                const fullDataUri = imageMatch[2];
                const mimeType = imageMatch[3].toLowerCase();
                const base64Data = fullDataUri.split(',')[1];

                const imageBuffer = Uint8Array.from(atob(base64Data), c => c.charCodeAt(0));

                let imgType: "png" | "jpeg" | "gif" | "bmp" | "svg" = "png";
                if (mimeType === 'jpg' || mimeType === 'jpeg') {
                    imgType = "jpeg";
                } else if (mimeType === 'svg+xml' || mimeType === 'svg') {
                    imgType = "svg";
                }

                docChildren.push(new Paragraph({
                    children: [
                        new ImageRun({
                            data: imageBuffer,
                            transformation: {
                                width: 300,
                                height: 300,
                            },
                            type: imgType
                        })
                    ],
                    alignment: AlignmentType.CENTER,
                    spacing: { before: 200, after: 200 }
                }));
            } catch (e) {
                console.error("Error embedding image in Docx", e);
            }
            continue;
        }

        // Limpar o texto da linha após verificar se era uma imagem
        const cleanedLine = cleanTextForExport(trimmed);
        if (!cleanedLine) continue;

        if (cleanedLine.startsWith('### ')) {
            docChildren.push(new Paragraph({
                text: cleanedLine.replace('### ', ''),
                heading: HeadingLevel.HEADING_3,
                spacing: { before: 200, after: 100 }
            }));
        } else if (cleanedLine.startsWith('## ')) {
            docChildren.push(new Paragraph({
                text: cleanedLine.replace('## ', ''),
                heading: HeadingLevel.HEADING_2,
                spacing: { before: 240, after: 120 }
            }));
        } else if (cleanedLine.startsWith('# ')) {
            docChildren.push(new Paragraph({
                text: cleanedLine.replace('# ', ''),
                heading: HeadingLevel.HEADING_1,
                spacing: { before: 280, after: 140 }
            }));
        } else if (cleanedLine.startsWith('- ') || cleanedLine.startsWith('* ')) {
             const textContent = cleanedLine.substring(2);
             const parts = parseBoldText(textContent);

             docChildren.push(new Paragraph({
                children: parts,
                bullet: { level: 0 }
            }));
        } else {
            const parts = parseBoldText(cleanedLine);
            docChildren.push(new Paragraph({
                children: parts,
                spacing: { after: 120 }
            }));
        }
    }

    const doc = new Document({
        sections: [{
            properties: {},
            children: docChildren,
        }],
    });

    const blob = await Packer.toBlob(doc);
    saveBlob(blob, `${subtitle.replace(/\s+/g, '_')}.docx`);
};

export const generateAndDownloadPdf = (title: string, subtitle: string, content: string) => {
    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    const margin = 20; 
    const maxLineWidth = pageWidth - (margin * 2);
    let yPos = 20;

    const drawPageBackground = () => {
        doc.setFillColor(THEME.bg[0], THEME.bg[1], THEME.bg[2]);
        doc.rect(0, 0, pageWidth, pageHeight, 'F');

        doc.setDrawColor(THEME.accent[0], THEME.accent[1], THEME.accent[2]);
        doc.setLineWidth(0.5);
        doc.line(margin, 15, pageWidth - margin, 15);

        doc.setFontSize(8);
        doc.setTextColor(THEME.accentSecondary[0], THEME.accentSecondary[1], THEME.accentSecondary[2]);
        doc.setFont("helvetica", "bold");
        doc.text("AGENTE UX", margin, 12);

        doc.setTextColor(100, 100, 100);
        doc.setFont("helvetica", "normal");
        doc.text(new Date().toLocaleDateString(), pageWidth - margin, 12, { align: "right" });
    };

    const checkPageBreak = (heightNeeded: number) => {
        if (yPos + heightNeeded > pageHeight - margin) {
            doc.addPage();
            drawPageBackground();
            yPos = 30;
            return true;
        }
        return false;
    };

    drawPageBackground();
    yPos = 30;

    // Document Title
    doc.setFontSize(22);
    doc.setTextColor(THEME.accent[0], THEME.accent[1], THEME.accent[2]);
    doc.setFont("helvetica", "bold");

    const splitTitle = doc.splitTextToSize(cleanTextForExport(title), maxLineWidth);
    splitTitle.forEach((line: string) => {
        doc.text(line, pageWidth / 2, yPos, { align: "center" });
        yPos += 10;
    });
    yPos += 5;

    // Document Subtitle
    doc.setFontSize(16);
    doc.setTextColor(THEME.textBold[0], THEME.textBold[1], THEME.textBold[2]);
    doc.setFont("helvetica", "normal");

    const splitSubtitle = doc.splitTextToSize(cleanTextForExport(subtitle), maxLineWidth);
    splitSubtitle.forEach((line: string) => {
        doc.text(line, pageWidth / 2, yPos, { align: "center" });
        yPos += 8;
    });
    yPos += 20;

    doc.setDrawColor(THEME.border[0], THEME.border[1], THEME.border[2]);
    doc.line(margin, yPos - 10, pageWidth - margin, yPos - 10);

    const BODY_FONT_SIZE = 10;
    const HEADER_1_SIZE = 16;
    const HEADER_2_SIZE = 14;
    const HEADER_3_SIZE = 12;

    doc.setFontSize(BODY_FONT_SIZE);

    const lines = content.split('\n');
    const imageRegex = /!\[(.*?)\]\((data:image\/(.*?);base64,.*?)\)/;
    const boldListItemRegex = /^([-*]|\d+\.)\s+\*\*(.*?)\*\*:?\s*(.*)$/;

    lines.forEach(line => {
        const trimmed = line.trim();

        if (!trimmed) {
            yPos += 4;
            checkPageBreak(5);
            return;
        }

        const imageMatch = trimmed.match(imageRegex);
        if (imageMatch) {
            try {
                const fullDataUri = imageMatch[2];
                const mimeType = imageMatch[3].toLowerCase();
                const imgHeight = 90; 
                const imgWidth = 90;
                checkPageBreak(imgHeight + 10);
                const xPos = (pageWidth - imgWidth) / 2;
                doc.setDrawColor(THEME.border[0], THEME.border[1], THEME.border[2]);
                doc.setFillColor(THEME.cardBg[0], THEME.cardBg[1], THEME.cardBg[2]);
                doc.roundedRect(xPos - 2, yPos - 2, imgWidth + 4, imgHeight + 4, 3, 3, 'FD');
                let format = 'PNG';
                if (mimeType === 'jpg' || mimeType === 'jpeg') format = 'JPEG';
                if (mimeType === 'webp') format = 'WEBP';
                doc.addImage(fullDataUri, format, xPos, yPos, imgWidth, imgHeight);
                yPos += imgHeight + 15;
            } catch (e) {
                console.error("Error adding image to PDF", e);
            }
            return;
        }

        // Limpar texto de emojis e HTML tags
        const cleanedLine = cleanTextForExport(trimmed);
        if (!cleanedLine) return;

        if (cleanedLine.startsWith('# ')) {
            const textToPrint = cleanedLine.replace('# ', '').replace(/\*\*/g, '');
            checkPageBreak(HEADER_1_SIZE);
            doc.setFont("helvetica", "bold");
            doc.setFontSize(HEADER_1_SIZE);
            doc.setTextColor(THEME.accent[0], THEME.accent[1], THEME.accent[2]);
            doc.text(textToPrint, margin, yPos + 4);
            yPos += HEADER_1_SIZE;
            return;
        } 

        if (cleanedLine.startsWith('## ')) {
            const textToPrint = cleanedLine.replace('## ', '').replace(/\*\*/g, '');
            checkPageBreak(HEADER_2_SIZE);
            doc.setFont("helvetica", "bold");
            doc.setFontSize(HEADER_2_SIZE);
            doc.setTextColor(THEME.accentSecondary[0], THEME.accentSecondary[1], THEME.accentSecondary[2]);
            doc.text(textToPrint, margin, yPos + 3);
            yPos += HEADER_2_SIZE;
            return;
        }

        if (cleanedLine.startsWith('### ')) {
            const textToPrint = cleanedLine.replace('### ', '').replace(/\*\*/g, '');
            checkPageBreak(HEADER_3_SIZE);
            doc.setFont("helvetica", "bold");
            doc.setFontSize(HEADER_3_SIZE);
            doc.setTextColor(THEME.textBold[0], THEME.textBold[1], THEME.textBold[2]);
            doc.text(textToPrint, margin, yPos + 2);
            yPos += HEADER_3_SIZE;
            return;
        }

        const boldHeaderMatch = cleanedLine.match(/^\*\*(.*?)\*\*:?\s*(.*)$/);
        if (boldHeaderMatch) {
            let key = boldHeaderMatch[1].trim().replace(/:$/, '');
            const contentPart = boldHeaderMatch[2].trim();

            const ORANGE_TITLES = [
                "Problemas e Oportunidades", "Contexto Geral", "Fatores Externos", "Soluções Potenciais",
                "Aplicabilidade do Negócio", "Aplicabilidade Técnica", "Aplicabilidade do Projeto",
                "Riscos do Projeto", "Ações"
            ];

            if (ORANGE_TITLES.some(t => key.toLowerCase() === t.toLowerCase() || key.includes(t))) {
                checkPageBreak(HEADER_3_SIZE + 4);
                doc.setFont("helvetica", "bold");
                doc.setFontSize(HEADER_3_SIZE);
                doc.setTextColor(THEME.accent[0], THEME.accent[1], THEME.accent[2]);
                doc.text(key + ":", margin, yPos + 2);
                yPos += HEADER_3_SIZE;

                if (contentPart) {
                     doc.setFont("helvetica", "normal");
                     doc.setFontSize(BODY_FONT_SIZE);
                     doc.setTextColor(THEME.text[0], THEME.text[1], THEME.text[2]);
                     const lineHeight = 5.5;
                     const splitContent = doc.splitTextToSize(contentPart, maxLineWidth);
                     splitContent.forEach((textLine: string) => {
                         if (yPos + lineHeight > pageHeight - margin) {
                            doc.addPage();
                            drawPageBackground();
                            yPos = 30;
                            doc.setFont("helvetica", "normal");
                            doc.setFontSize(BODY_FONT_SIZE);
                            doc.setTextColor(THEME.text[0], THEME.text[1], THEME.text[2]);
                         }
                         doc.text(textLine, margin, yPos);
                         yPos += lineHeight;
                     });
                     yPos += 2;
                }
                return;
            }
        }

        const boldItemMatch = cleanedLine.match(boldListItemRegex);
        if (boldItemMatch) {
            const rawTitle = boldItemMatch[2].trim().replace(/:$/, '');
            const title = rawTitle + ":"; 
            const contentPart = boldItemMatch[3].trim();
            const lineHeight = 5.5;
            doc.setFontSize(BODY_FONT_SIZE);
            doc.setFont("helvetica", "normal");
            const contentLines = doc.splitTextToSize(contentPart, maxLineWidth);
            const totalBlockHeight = lineHeight + (contentLines.length * lineHeight);
            checkPageBreak(totalBlockHeight + 2);
            doc.setFont("helvetica", "bold");
            doc.setTextColor(THEME.textBold[0], THEME.textBold[1], THEME.textBold[2]);
            doc.text(title, margin, yPos);
            yPos += lineHeight;
            doc.setFont("helvetica", "normal");
            doc.setTextColor(THEME.text[0], THEME.text[1], THEME.text[2]);
            doc.text(contentLines, margin, yPos);
            yPos += (contentLines.length * lineHeight) + 2;
            return;
        }

        let textToPrint = cleanedLine.replace(/\*\*/g, '');
        if (textToPrint.startsWith('- ') || textToPrint.startsWith('* ')) {
            textToPrint = textToPrint.substring(2);
        } else if (/^\d+\.\s/.test(textToPrint)) {
            textToPrint = textToPrint.replace(/^\d+\.\s/, '');
        }

        doc.setFont("helvetica", "normal");
        doc.setFontSize(BODY_FONT_SIZE);
        const lineHeight = 5.5; 
        const splitText = doc.splitTextToSize(textToPrint, maxLineWidth);
        const blockHeight = splitText.length * lineHeight;
        checkPageBreak(blockHeight + 2);
        doc.setFont("helvetica", "normal");
        doc.setFontSize(BODY_FONT_SIZE);
        doc.setTextColor(THEME.text[0], THEME.text[1], THEME.text[2]);
        splitText.forEach((textLine: string) => {
             if (yPos + lineHeight > pageHeight - margin) {
                doc.addPage();
                drawPageBackground();
                yPos = 30;
                doc.setFont("helvetica", "normal");
                doc.setFontSize(BODY_FONT_SIZE);
                doc.setTextColor(THEME.text[0], THEME.text[1], THEME.text[2]);
             }
             doc.text(textLine, margin, yPos);
             yPos += lineHeight;
        });
        yPos += 2;
    });

    doc.save(`${subtitle.replace(/\s+/g, '_')}.pdf`);
};

const parseBoldText = (text: string): TextRun[] => {
    const parts: TextRun[] = [];
    const regex = /\*\*(.*?)\*\*/g;
    let lastIndex = 0;
    let match;

    while ((match = regex.exec(text)) !== null) {
        if (match.index > lastIndex) {
            parts.push(new TextRun(text.substring(lastIndex, match.index)));
        }
        parts.push(new TextRun({
            text: match[1],
            bold: true,
        }));
        lastIndex = regex.lastIndex;
    }
    if (lastIndex < text.length) {
        parts.push(new TextRun(text.substring(lastIndex)));
    }
    return parts;
};

const saveBlob = (blob: Blob, fileName: string) => {
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    document.body.appendChild(a);
    a.style.display = "none";
    a.href = url;
    a.download = fileName;
    a.click();
    window.URL.revokeObjectURL(url);
    document.body.removeChild(a);
};

import { GoogleGenAI, Type } from "@google/genai";
import { ArtifactType, GeneratedArtifact } from '../types';

const API_KEY = process.env.API_KEY;
if (!API_KEY) {
    throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const safeParseJson = (jsonString: string): any => {
    const match = jsonString.match(/```(json)?\s*([\s\S]*?)\s*```/);
    let textToParse = jsonString.trim();

    if (match && match[2]) {
        textToParse = match[2];
    } else {
        const firstBrace = textToParse.indexOf('{');
        const lastBrace = textToParse.lastIndexOf('}');
        const firstBracket = textToParse.indexOf('[');
        const lastBracket = textToParse.lastIndexOf(']');

        if (firstBracket !== -1 && lastBracket !== -1 && (firstBrace === -1 || firstBracket < firstBrace)) {
             textToParse = textToParse.substring(firstBracket, lastBracket + 1);
        } else if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
            textToParse = textToParse.substring(firstBrace, lastBrace + 1);
        }
    }

    try {
        let parsed = JSON.parse(textToParse);
        if (typeof parsed === 'string') {
            parsed = JSON.parse(parsed);
        }
        return parsed;
    } catch (error) {
        console.error("Failed to parse JSON:", textToParse);
        return null;
    }
};

const cleanMermaidCode = (code: string): string => {
    if (!code) return '';
    let clean = code
        .replace(/```mermaid/gi, '')
        .replace(/```/g, '')
        .replace(/<br\s*\/?>/gi, '\\n')
        .replace(/<[^>]*>/g, '');
    clean = clean.trim();
    const lines = clean.split('\n');
    const keywords = ['graph', 'flowchart', 'sequenceDiagram', 'classDiagram', 'stateDiagram', 'stateDiagram-v2', 'erDiagram', 'gantt', 'pie', 'journey', 'mindmap', 'timeline'];
    let startLineIndex = -1;
    for (let i = 0; i < lines.length; i++) {
      const trimmedLine = lines[i].trim();
      if (keywords.some(kw => trimmedLine.startsWith(kw))) {
        startLineIndex = i;
        break;
      }
    }
    if (startLineIndex !== -1) {
      clean = lines.slice(startLineIndex).join('\n');
    } else if (clean.includes('-->') || clean.includes('---')) {
        clean = 'graph TD\n' + clean;
    }
    clean = clean.replace(/`/g, "'");
    return clean.trim();
};

