import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, ImageRun } from "docx";
import { jsPDF } from "jspdf";

// App Theme Colors for PDF
const THEME = {
    bg: [9, 9, 11],         // Zinc 950
    cardBg: [24, 24, 27],   // Zinc 900
    text: [228, 228, 231],  // Zinc 200 (Brighter for better contrast)
    textBold: [255, 255, 255], // White
    accent: [249, 115, 22], // Orange 500
    accentSecondary: [251, 191, 36], // Amber 400
    border: [63, 63, 70]    // Zinc 700
};

/**
 * Limpa o texto removendo tags HTML e emojis para garantir compatibilidade
 * e atender aos requisitos de exportação limpa.
 */
const cleanTextForExport = (text: string): string => {
    if (!text) return "";

    // 1. Remover tags HTML (ex: <br>, <div>, etc)
    let cleaned = text.replace(/<[^>]*>/g, '');

    // 2. Remover Emojis usando regex de ranges Unicode
    cleaned = cleaned.replace(/([\u2700-\u27BF]|[\uE000-\uF8FF]|\uD83C[\uDC00-\uDFFF]|\uD83D[\uDC00-\uDFFF]|[\u2011-\u26FF]|\uD83E[\uDD10-\uDDFF])/g, '');

    return cleaned;
};

export const generateAndDownloadDocx = async (title: string, subtitle: string, content: string) => {
    const lines = content.split('\n');
    const docChildren: (Paragraph)[] = [];

    docChildren.push(
        new Paragraph({
            text: cleanTextForExport(title),
            heading: HeadingLevel.TITLE,
            alignment: AlignmentType.CENTER,
            spacing: { after: 300 },
        })
    );

    docChildren.push(
        new Paragraph({
            text: cleanTextForExport(subtitle),
            heading: HeadingLevel.HEADING_2,
            alignment: AlignmentType.CENTER,
            spacing: { after: 300 },
        })
    );

    const imageRegex = /!\[(.*?)\]\((data:image\/(.*?);base64,.*?)\)/;

    for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) {
            docChildren.push(new Paragraph({ text: "" }));
            continue;
        }

        const imageMatch = trimmed.match(imageRegex);

        if (imageMatch) {
            try {
                const fullDataUri = imageMatch[2];
                const mimeType = imageMatch[3].toLowerCase();
                const base64Data = fullDataUri.split(',')[1];

                const imageBuffer = Uint8Array.from(atob(base64Data), c => c.charCodeAt(0));

                let imgType: "png" | "jpeg" | "gif" | "bmp" | "svg" = "png";
                if (mimeType === 'jpg' || mimeType === 'jpeg') {
                    imgType = "jpeg";
                } else if (mimeType === 'svg+xml' || mimeType === 'svg') {
                    imgType = "svg";
                }

                docChildren.push(new Paragraph({
                    children: [
                        new ImageRun({
                            data: imageBuffer,
                            transformation: {
                                width: 300,
                                height: 300,
                            },
                            type: imgType
                        })
                    ],
                    alignment: AlignmentType.CENTER,
                    spacing: { before: 200, after: 200 }
                }));
            } catch (e) {
                console.error("Error embedding image in Docx", e);
            }
            continue;
        }

        const cleanedLine = cleanTextForExport(trimmed);
        if (!cleanedLine) continue;

        if (cleanedLine.startsWith('Módulo:') || cleanedLine.startsWith('MÓDULO:')) {
            docChildren.push(new Paragraph({
                children: [
                    new TextRun({
                        text: cleanedLine,
                        color: "F97316", // Laranja solicitado
                        bold: true,
                    })
                ],
                heading: HeadingLevel.HEADING_2,
                spacing: { before: 240, after: 120 }
            }));
        } else if (cleanedLine.startsWith('### ')) {
            docChildren.push(new Paragraph({
                text: cleanedLine.replace('### ', ''),
                heading: HeadingLevel.HEADING_3,
                spacing: { before: 200, after: 100 }
            }));
        } else if (cleanedLine.startsWith('## ')) {
            docChildren.push(new Paragraph({
                text: cleanedLine.replace('## ', ''),
                heading: HeadingLevel.HEADING_2,
                spacing: { before: 240, after: 120 }
            }));
        } else if (cleanedLine.startsWith('# ')) {
            docChildren.push(new Paragraph({
                text: cleanedLine.replace('# ', ''),
                heading: HeadingLevel.HEADING_1,
                spacing: { before: 280, after: 140 }
            }));
        } else {
            const parts = parseBoldText(cleanedLine);
            docChildren.push(new Paragraph({
                children: parts,
                spacing: { after: 120 },
                bullet: (cleanedLine.startsWith('- ') || cleanedLine.startsWith('* ')) ? { level: 0 } : undefined
            }));
        }
    }

    const doc = new Document({
        sections: [{
            properties: {},
            children: docChildren,
        }],
    });

    const blob = await Packer.toBlob(doc);
    saveBlob(blob, `${subtitle.replace(/\s+/g, '_')}.docx`);
};

export const generateAndDownloadPdf = (title: string, subtitle: string, content: string) => {
    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    const margin = 20; 
    const maxLineWidth = pageWidth - (margin * 2);
    let yPos = 20;

    const drawPageBackground = () => {
        doc.setFillColor(THEME.bg[0], THEME.bg[1], THEME.bg[2]);
        doc.rect(0, 0, pageWidth, pageHeight, 'F');

        doc.setDrawColor(THEME.accent[0], THEME.accent[1], THEME.accent[2]);
        doc.setLineWidth(0.5);
        doc.line(margin, 15, pageWidth - margin, 15);

        doc.setFontSize(8);
        doc.setTextColor(THEME.accentSecondary[0], THEME.accentSecondary[1], THEME.accentSecondary[2]);
        doc.setFont("helvetica", "bold");
        doc.text("AGENTE UX", margin, 12);

        doc.setTextColor(100, 100, 100);
        doc.setFont("helvetica", "normal");
        doc.text(new Date().toLocaleDateString(), pageWidth - margin, 12, { align: "right" });
    };

    const checkPageBreak = (heightNeeded: number) => {
        if (yPos + heightNeeded > pageHeight - margin) {
            doc.addPage();
            drawPageBackground();
            yPos = 30;
            return true;
        }
        return false;
    }

    drawPageBackground();
    yPos = 30;

    doc.setFontSize(22);
    doc.setTextColor(THEME.accent[0], THEME.accent[1], THEME.accent[2]);
    doc.setFont("helvetica", "bold");

    const splitTitle = doc.splitTextToSize(cleanTextForExport(title), maxLineWidth);
    splitTitle.forEach((line: string) => {
        doc.text(line, pageWidth / 2, yPos, { align: "center" });
        yPos += 10;
    });
    yPos += 5;

    doc.setFontSize(16);
    doc.setTextColor(THEME.textBold[0], THEME.textBold[1], THEME.textBold[2]);
    doc.setFont("helvetica", "normal");

    const splitSubtitle = doc.splitTextToSize(cleanTextForExport(subtitle), maxLineWidth);
    splitSubtitle.forEach((line: string) => {
        doc.text(line, pageWidth / 2, yPos, { align: "center" });
        yPos += 8;
    });
    yPos += 20;

    doc.setDrawColor(THEME.border[0], THEME.border[1], THEME.border[2]);
    doc.line(margin, yPos - 10, pageWidth - margin, yPos - 10);

    const BODY_FONT_SIZE = 10;
    const HEADER_1_SIZE = 16;
    const HEADER_2_SIZE = 14;
    const HEADER_3_SIZE = 12;

    doc.setFontSize(BODY_FONT_SIZE);

    const lines = content.split('\n');
    const imageRegex = /!\[(.*?)\]\((data:image\/(.*?);base64,.*?)\)/;

    lines.forEach(line => {
        const trimmed = line.trim();

        if (!trimmed) {
            yPos += 4;
            checkPageBreak(5);
            return;
        }

        const imageMatch = trimmed.match(imageRegex);
        if (imageMatch) {
            try {
                const fullDataUri = imageMatch[2];
                const mimeType = imageMatch[3].toLowerCase();
                const imgHeight = 90; 
                const imgWidth = 90;
                checkPageBreak(imgHeight + 10);
                const xPos = (pageWidth - imgWidth) / 2;
                doc.setDrawColor(THEME.border[0], THEME.border[1], THEME.border[2]);
                doc.setFillColor(THEME.cardBg[0], THEME.cardBg[1], THEME.cardBg[2]);
                doc.roundedRect(xPos - 2, yPos - 2, imgWidth + 4, imgHeight + 4, 3, 3, 'FD');
                let format = 'PNG';
                if (mimeType === 'jpg' || mimeType === 'jpeg') format = 'JPEG';
                if (mimeType === 'webp') format = 'WEBP';
                doc.addImage(fullDataUri, format, xPos, yPos, imgWidth, imgHeight);
                yPos += imgHeight + 15;
            } catch (e) {
                console.error("Error adding image to PDF", e);
            }
            return;
        }

        const cleanedLine = cleanTextForExport(trimmed);
        if (!cleanedLine) return;

        // Título do Módulo (Laranja)
        if (cleanedLine.startsWith('Módulo:') || cleanedLine.startsWith('MÓDULO:')) {
            checkPageBreak(HEADER_2_SIZE + 5);
            doc.setFont("helvetica", "bold");
            doc.setFontSize(HEADER_2_SIZE);
            doc.setTextColor(THEME.accent[0], THEME.accent[1], THEME.accent[2]); 
            doc.text(cleanedLine, margin, yPos);
            yPos += HEADER_2_SIZE;
            return;
        }

        // Cabeçalhos (Hierarquia)
        if (cleanedLine.startsWith('# ')) {
            const textToPrint = cleanedLine.replace('# ', '').replace(/\*\*/g, '');
            checkPageBreak(HEADER_1_SIZE);
            doc.setFont("helvetica", "bold");
            doc.setFontSize(HEADER_1_SIZE);
            doc.setTextColor(THEME.textBold[0], THEME.textBold[1], THEME.textBold[2]);
            doc.text(textToPrint, margin, yPos + 4);
            yPos += HEADER_1_SIZE;
            return;
        } 

        if (cleanedLine.startsWith('## ')) {
            const textToPrint = cleanedLine.replace('## ', '').replace(/\*\*/g, '');
            checkPageBreak(HEADER_2_SIZE);
            doc.setFont("helvetica", "bold");
            doc.setFontSize(HEADER_2_SIZE);
            doc.setTextColor(THEME.textBold[0], THEME.textBold[1], THEME.textBold[2]);
            doc.text(textToPrint, margin, yPos + 3);
            yPos += HEADER_2_SIZE;
            return;
        }

        if (cleanedLine.startsWith('### ')) {
            const textToPrint = cleanedLine.replace('### ', '').replace(/\*\*/g, '');
            checkPageBreak(HEADER_3_SIZE);
            doc.setFont("helvetica", "bold");
            doc.setFontSize(HEADER_3_SIZE);
            doc.setTextColor(THEME.textBold[0], THEME.textBold[1], THEME.textBold[2]);
            doc.text(textToPrint, margin, yPos + 2);
            yPos += HEADER_3_SIZE;
            return;
        }

        const lineHeight = 5.5;
        doc.setFontSize(BODY_FONT_SIZE);

        // Detecta padrão de rótulo em negrito (**Chave:** Conteúdo)
        const boldHeaderMatch = cleanedLine.match(/^\*\*(.*?)\*\*:(.*)$/);

        if (boldHeaderMatch) {
            const label = boldHeaderMatch[1] + ":";
            const content = boldHeaderMatch[2].trim();

            // Especial para Observações em branco (textBold)
            const isObservation = label.toLowerCase().includes("observações");

            // Rótulo
            doc.setFont("helvetica", "bold");
            doc.setTextColor(isObservation ? THEME.textBold[0] : THEME.text[0], isObservation ? THEME.textBold[1] : THEME.text[1], isObservation ? THEME.textBold[2] : THEME.text[2]);

            const labelWidth = doc.getTextWidth(label);
            checkPageBreak(lineHeight + 2);
            doc.text(label, margin, yPos);

            // Conteúdo (Lidar com parágrafo quebrado forçando quebra para nova linha se for muito longo)
            doc.setFont("helvetica", "normal");
            doc.setTextColor(THEME.text[0], THEME.text[1], THEME.text[2]);

            // Se o conteúdo for maior que 30 caracteres, jogamos para a linha de baixo para evitar "formatação quebrada"
            if (content.length > 30) {
                yPos += lineHeight;
                const splitContent = doc.splitTextToSize(content, maxLineWidth);
                splitContent.forEach((cl: string) => {
                    checkPageBreak(lineHeight);
                    doc.text(cl, margin, yPos);
                    yPos += lineHeight;
                });
            } else {
                doc.text(content, margin + labelWidth + 2, yPos);
                yPos += lineHeight;
            }

            yPos += 2;
            return;
        }

        // Renderização padrão para linhas comuns
        doc.setFont("helvetica", "normal");
        doc.setTextColor(THEME.text[0], THEME.text[1], THEME.text[2]);
        const splitText = doc.splitTextToSize(cleanedLine.replace(/\*\*/g, ''), maxLineWidth);
        splitText.forEach((tLine: string) => {
            checkPageBreak(lineHeight);
            doc.text(tLine, margin, yPos);
            yPos += lineHeight;
        });
        yPos += 2;
    });

    doc.save(`${subtitle.replace(/\s+/g, '_')}.pdf`);
};

const parseBoldText = (text: string): TextRun[] => {
    const parts: TextRun[] = [];
    const regex = /\*\*(.*?)\*\*/g;
    let lastIndex = 0;
    let match;

    while ((match = regex.exec(text)) !== null) {
        if (match.index > lastIndex) {
            parts.push(new TextRun(text.substring(lastIndex, match.index)));
        }
        parts.push(new TextRun({
            text: match[1],
            bold: true,
        }));
        lastIndex = regex.lastIndex;
    }
    if (lastIndex < text.length) {
        parts.push(new TextRun(text.substring(lastIndex)));
    }
    return parts;
};

const saveBlob = (blob: Blob, fileName: string) => {
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    document.body.appendChild(a);
    a.style.display = "none";
    a.href = url;
    a.download = fileName;
    a.click();
    window.URL.revokeObjectURL(url);
    document.body.removeChild(a);
};

import React, { useEffect, useRef, useState } from 'react';
import { GeneratedArtifact } from '../types';
import { DocumentTextIcon } from './Icons';

declare global {
    interface Window {
        mermaid?: {
            run: (options: { nodes: Array<Element> }) => void;
        }
    }
}

interface ArtifactDisplayProps {
    artifact: GeneratedArtifact;
}

const ArtifactDisplay: React.FC<ArtifactDisplayProps> = ({ artifact }) => {
    const mermaidRef = useRef<HTMLDivElement>(null);
    const [renderError, setRenderError] = useState<string | null>(null);

    useEffect(() => {
        const renderMermaid = async () => {
             if (window.mermaid && mermaidRef.current) {
                const nodes = Array.from(mermaidRef.current.querySelectorAll('.mermaid')) as Element[];
                if (nodes.length > 0) {
                     nodes.forEach(node => node.removeAttribute('data-processed'));
                     try {
                        await window.mermaid.run({ nodes: nodes });
                        setRenderError(null);
                     } catch (err: any) {
                         console.error("Mermaid Render Error:", err);
                         setRenderError("Erro de sintaxe no diagrama gerado. Exibindo código fonte.");
                     }
                }
            }
        };
        const timeoutId = setTimeout(() => { renderMermaid(); }, 100);
        return () => clearTimeout(timeoutId);
    }, [artifact]);

    const downloadMermaidAsPng = (containerId: string, filename: string) => {
        const container = document.getElementById(containerId);
        if (!container) return;
        const svg = container.querySelector('svg');
        if (!svg) return;
        const viewBox = svg.getAttribute('viewBox');
        let sourceWidth = svg.getBoundingClientRect().width;
        let sourceHeight = svg.getBoundingClientRect().height;
        if (viewBox) {
            const parts = viewBox.split(/\s+|,/).filter(p => p.trim() !== '');
            if (parts.length === 4) { sourceWidth = parseFloat(parts[2]); sourceHeight = parseFloat(parts[3]); }
        }
        if (sourceWidth < 10) sourceWidth = 800;
        if (sourceHeight < 10) sourceHeight = 600;
        const serializer = new XMLSerializer();
        let source = serializer.serializeToString(svg);
        if (!source.match(/^<svg[^>]+xmlns="http\:\/\/www\.w3\.org\/2000\/svg"/)) {
            source = source.replace(/^<svg/, '<svg xmlns="http://www.w3.org/2000/svg"');
        }
        const img = new Image();
        const svgBlob = new Blob([source], { type: 'image/svg+xml;charset=utf-8' });
        const url = URL.createObjectURL(svgBlob);
        img.onload = function () {
            const canvas = document.createElement('canvas');
            const scale = 4;
            const padding = 40;
            canvas.width = (sourceWidth + padding * 2) * scale;
            canvas.height = (sourceHeight + padding * 2) * scale;
            const ctx = canvas.getContext('2d');
            if (ctx) {
                ctx.fillStyle = "#18181b";
                ctx.fillRect(0, 0, canvas.width, canvas.height);
                ctx.scale(scale, scale);
                ctx.drawImage(img, padding, padding, sourceWidth, sourceHeight);
                const imgURI = canvas.toDataURL('image/png');
                const a = document.createElement('a');
                a.setAttribute('download', `${filename}.png`);
                a.setAttribute('href', imgURI);
                a.click();
            }
            URL.revokeObjectURL(url);
        };
        img.src = url;
    };

    const downloadJsonFile = (jsonText: string) => {
        try {
            const obj = JSON.parse(jsonText);
            const blob = new Blob([JSON.stringify(obj, null, 2)], { type: 'application/json' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `base_conhecimento_${Date.now()}.json`;
            a.click();
            URL.revokeObjectURL(url);
        } catch (e) { alert("Erro ao formatar JSON para download."); }
    };

    const renderStyledText = (text: string) => {
        const lines = text.split('\n');
        return lines.map((line, i) => {
            // Títulos de Módulo em Laranja
            if (line.trim().startsWith('Módulo:') || line.trim().startsWith('MÓDULO:')) {
                return <div key={i} className="text-orange-500 font-bold text-lg mt-6 mb-2">{line}</div>;
            }

            // Requisitos em Negrito
            if (line.trim().startsWith('**Requisito') || line.trim().startsWith('Requisito #')) {
                const content = line.replace(/\*\*/g, '');
                return <div key={i} className="font-bold text-gray-100 mt-4 mb-1">{content}</div>;
            }

            return <div key={i} className="mb-1">{line}</div>;
        });
    };

    if (artifact.isJson) {
        return (
            <div className="space-y-6">
                <div className="flex items-center gap-2 mb-2 border-b border-white/10 pb-4">
                    <span className="p-2 bg-amber-500/20 rounded-lg text-amber-300"><DocumentTextIcon /></span>
                    <h3 className="text-lg font-bold text-gray-100">Base de Conhecimento Estruturada</h3>
                </div>
                <div className="p-5 bg-zinc-900/40 rounded-xl border border-white/5 text-gray-300 text-sm leading-relaxed shadow-inner">
                    A Base de Conhecimento foi gerada com sucesso e contém todo o histórico do projeto consolidado.
                </div>
                <button onClick={() => downloadJsonFile(artifact.text)} className="w-full flex items-center justify-center gap-3 px-6 py-4 rounded-xl bg-amber-600 text-white hover:bg-amber-500 transition-all font-bold shadow-lg">Baixar .JSON</button>
            </div>
        );
    }

    if (artifact.multiArtifacts && artifact.multiArtifacts.length > 0) {
        return (
            <div ref={mermaidRef} className="space-y-12">
                {artifact.multiArtifacts.map((sub, index) => {
                    const uniqueId = `mermaid-multi-${index}-${Date.now()}`;
                    return (
                        <div key={index} className="flex flex-col bg-zinc-900/40 border border-white/5 rounded-2xl overflow-hidden shadow-lg">
                            <div className="bg-zinc-800/60 px-6 py-4 border-b border-white/5"><h4 className="text-gray-100 font-bold">{sub.title}</h4></div>
                            <div className="p-6 bg-[#0f0f11] flex justify-center w-full">
                                {sub.type === 'mermaid' ? (<div id={uniqueId} className="w-full flex justify-center"><pre className="mermaid bg-transparent text-center w-full">{sub.content}</pre></div>) : (<div className="whitespace-pre-wrap text-sm text-gray-300">{sub.content}</div>)}
                            </div>
                            {sub.type === 'mermaid' && (<div className="px-6 py-4 bg-zinc-800/40 border-t border-white/5 flex justify-end"><button onClick={() => downloadMermaidAsPng(uniqueId, sub.title.replace(/\s+/g, '_'))} className="flex items-center gap-2 px-4 py-2 rounded-lg bg-sky-600/20 text-sky-300 hover:bg-sky-600/30 border border-sky-500/30 transition-all text-sm font-medium">Baixar PNG</button></div>)}
                        </div>
                    );
                })}
            </div>
        );
    }

    if (artifact.isMermaid) {
        const uniqueId = `mermaid-single-${Date.now()}`;
        return (
            <div ref={mermaidRef}>
                <div id={uniqueId} className="bg-zinc-900/60 backdrop-blur-md p-6 rounded-xl border border-white/10 shadow-inner w-full flex justify-center mb-3"><pre className="mermaid text-center w-full">{artifact.text}</pre></div>
                <button onClick={() => downloadMermaidAsPng(uniqueId, 'diagrama')} className="w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl bg-sky-600/20 text-sky-300 hover:bg-sky-600/30 border border-sky-500/30 transition-all">Baixar PNG</button>
            </div>
        );
    }

    if (artifact.imageUrl) {
         return (
            <div className="space-y-4">
                <div className="flex justify-center w-full"><div className="relative rounded-xl overflow-hidden shadow-2xl border-4 border-zinc-800/50 w-full max-w-sm"><img src={artifact.imageUrl} alt="Artefato Gerado" className="w-full h-full object-cover" /></div></div>
                 <div className="prose prose-invert prose-sm max-w-none bg-zinc-950/40 backdrop-blur-sm p-4 rounded-xl border border-white/5 shadow-inner opacity-80"><div className="whitespace-pre-wrap font-sans text-gray-300 leading-relaxed text-sm line-clamp-3">{artifact.text}</div></div>
            </div>
         )
    }

    return (
        <div className="space-y-3">
            <div className="text-xs font-bold text-orange-400 uppercase tracking-wider ml-1">Artefato Gerado</div>
            <div className="prose prose-invert prose-sm sm:prose-base max-w-none bg-zinc-950/40 backdrop-blur-sm p-6 rounded-2xl border border-white/5 shadow-inner relative overflow-hidden">
                <div className="whitespace-pre-wrap font-sans text-gray-200 leading-relaxed">
                    {renderStyledText(artifact.text)}
                </div>
            </div>
        </div>
    );
};

